{
  "name": "Ubuntu Intelligence",
  "description": "A sophisticated web-based Ubuntu desktop environment featuring an AI-powered terminal driven by Gemini 3 Flash. Experience the familiar Yaru interface with intelligent system assistance."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AppID = 'terminal' | 'files' | 'browser' | 'settings' | 'about';

export interface WindowState {
  id: AppID;
  title: string;
  isOpen: boolean;
  isMaximized: boolean;
  zIndex: number;
}

export interface TerminalLine {
  type: 'input' | 'output' | 'error' | 'system';
  content: string;
}

import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async processCommand(command: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: command,
        config: {
          systemInstruction: `You are 'Ubuntu Intelligence', an integrated AI assistant for a web-based Ubuntu desktop environment. 
          Users interact with you via a terminal. 
          - If the user asks for Linux commands, provide them clearly.
          - If they ask general questions, respond helpfully but stay in the persona of a system assistant.
          - Keep responses concise and formatted for a terminal (monospaced friendly).
          - Use a bit of tech-savvy Ubuntu personality.`,
          temperature: 0.7,
        },
      });

      return response.text || "No response received from the system.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return `Error: ${error instanceof Error ? error.message : 'Unknown system failure.'}`;
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect } from 'react';

const TopBar: React.FC = () => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formattedDate = time.toLocaleDateString('en-GB', {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
  });

  const formattedTime = time.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit',
  });

  return (
    <div className="h-7 w-full bg-black/40 backdrop-blur-md flex items-center justify-between px-4 text-[13px] font-medium z-50 select-none border-b border-white/5">
      <div className="flex items-center space-x-4">
        <span className="cursor-default hover:text-white/80">Activities</span>
      </div>

      <div className="flex items-center absolute left-1/2 -translate-x-1/2 cursor-default hover:bg-white/10 px-2 rounded h-full transition-colors">
        <span>{formattedDate} {formattedTime}</span>
      </div>

      <div className="flex items-center space-x-4">
        <div className="flex items-center space-x-3">
          <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
            <path d="M12 21l-12-18h24z" />
          </svg>
          <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
            <path d="M15.67 4H14V2h-4v2H8.33C7.6 4 7 4.6 7 5.33v15.33C7 21.4 7.6 22 8.33 22h7.33c.74 0 1.34-.6 1.34-1.34V5.33C17 4.6 16.4 4 15.67 4z" />
          </svg>
          <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
            <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" />
          </svg>
        </div>
      </div>
    </div>
  );
};

export default TopBar;

