import React, { ReactNode } from 'react';
import { AppID } from '../types';

interface WindowProps {
  id: AppID;
  title: string;
  isOpen: boolean;
  isMaximized: boolean;
  zIndex: number;
  onClose: () => void;
  onMaximize: () => void;
  onFocus: () => void;
  children: ReactNode;
  icon?: string;
}

const Window: React.FC<WindowProps> = ({
  id,
  title,
  isOpen,
  isMaximized,
  zIndex,
  onClose,
  onMaximize,
  onFocus,
  children,
  icon
}) => {
  if (!isOpen) return null;

  const windowClasses = isMaximized
    ? "fixed inset-0 top-7 left-[68px] z-[zIndex]"
    : "fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] max-w-[800px] h-[70vh] rounded-lg shadow-2xl overflow-hidden";

  return (
    <div 
      className={`${windowClasses} bg-[#3D3D3D] flex flex-col border border-white/10`}
      style={{ zIndex }}
      onClick={onFocus}
    >
      {/* Title Bar */}
      <div className="h-10 bg-[#2D2D2D] flex items-center justify-between px-4 cursor-default select-none border-b border-white/5">
        <div className="flex items-center space-x-3 text-sm font-medium text-gray-200">
          {icon && <img src={icon} alt="" className="w-4 h-4" />}
          <span>{title}</span>
        </div>

        <div className="flex items-center space-x-2">
          {/* Close, Minimize, Maximize buttons - Ubuntu style uses orange/dark circles */}
          <button 
            onClick={onClose}
            className="w-6 h-6 rounded-full bg-[#E95420] flex items-center justify-center hover:opacity-80 transition-opacity"
          >
            <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
          <button 
            onClick={onMaximize}
            className="w-6 h-6 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/20 transition-all"
          >
            <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
            </svg>
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-hidden relative">
        {children}
      </div>
    </div>
  );
};

export default Window;

import React, { useState, useRef, useEffect } from 'react';
import { TerminalLine } from '../../types';
import { geminiService } from '../../services/geminiService';

const Terminal: React.FC = () => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Welcome to Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * Documentation:  https://help.ubuntu.com' },
    { type: 'system', content: ' * Management:     https://landscape.canonical.com' },
    { type: 'system', content: ' * Support:        https://ubuntu.com/advantage' },
    { type: 'system', content: '' },
    { type: 'system', content: 'Ubuntu Intelligence ready. Type your query or help.' },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [lines, isProcessing]);

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isProcessing) return;

    const cmd = inputValue.trim();
    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console cleared. Ubuntu Intelligence standing by.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: 'Available commands: clear, help, whoami, info, or just ask any question!' }
      ]);
      setIsProcessing(false);
      return;
    }

    const response = await geminiService.processCommand(cmd);
    setLines(prev => [...prev, { type: 'output', content: response }]);
    setIsProcessing(false);
  };

  return (
    <div 
      className="h-full bg-[#300A24] text-[#FFFFFF] p-4 ubuntu-terminal overflow-y-auto no-scrollbar selection:bg-[#E95420] selection:text-white cursor-text"
      ref={scrollRef}
      onClick={() => inputRef.current?.focus()}
    >
      <div className="space-y-1">
        {lines.map((line, i) => (
          <div key={i} className="break-words">
            {line.type === 'input' && (
              <span className="flex">
                <span className="text-[#87ff5f] font-bold">ubuntu@intelligence</span>
                <span className="text-white mr-2">:~$</span>
                <span className="flex-1">{line.content}</span>
              </span>
            )}
            {line.type === 'output' && (
              <div className="whitespace-pre-wrap pl-2 border-l-2 border-white/10 mb-2 py-1 text-gray-200">
                {line.content}
              </div>
            )}
            {line.type === 'system' && (
              <div className="text-gray-400 opacity-80">{line.content}</div>
            )}
            {line.type === 'error' && (
              <div className="text-red-400">{line.content}</div>
            )}
          </div>
        ))}
        {isProcessing && (
          <div className="flex items-center space-x-2 text-gray-400 italic">
            <span className="animate-pulse">Processing request...</span>
          </div>
        )}
        <form onSubmit={handleCommand} className="flex">
          <span className="text-[#87ff5f] font-bold whitespace-nowrap">ubuntu@intelligence</span>
          <span className="text-white mr-2">:~$</span>
          <input
            ref={inputRef}
            autoFocus
            className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0 terminal-input"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            disabled={isProcessing}
          />
        </form>
      </div>
    </div>
  );
};

export default Terminal;

