import React, { useState, useRef, useEffect } from 'react';

const Browser: React.FC = () => {
  const defaultUrl = 'https://www.wikipedia.org';
  const [urlInput, setUrlInput] = useState(defaultUrl);
  const [iframeUrl, setIframeUrl] = useState(defaultUrl);
  const [history, setHistory] = useState<string[]>([defaultUrl]);
  const [isLoading, setIsLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const navigateTo = (url: string) => {
    let formattedUrl = url.trim();
    if (!formattedUrl.startsWith('http://') && !formattedUrl.startsWith('https://')) {
      formattedUrl = 'https://' + formattedUrl;
    }
    setIframeUrl(formattedUrl);
    setUrlInput(formattedUrl);
    setHistory(prev => {
      // Keep only unique history items, move the most recent to the top
      const newHistory = [formattedUrl, ...prev.filter(item => item !== formattedUrl)];
      return newHistory.slice(0, 20); // Limit to last 20 entries
    });
    setIsHistoryOpen(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      navigateTo(urlInput);
    }
  };

  const handleLoad = () => {
    setIsLoading(false);
  };

  const clearHistory = () => {
    setHistory([iframeUrl]);
    setIsHistoryOpen(false);
  };

  return (
    <div className="h-full flex flex-col bg-white select-none">
      {/* Browser Toolbar */}
      <div className="h-12 bg-[#F2F2F2] border-b border-gray-300 flex items-center px-2 space-x-2 shrink-0 relative">
        <div className="flex items-center space-x-1 pr-2 border-r border-gray-300">
          <button 
            onClick={() => window.history.back()}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Back"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <button 
            onClick={() => window.history.forward()}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Forward"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
          <button 
            onClick={() => {
              setIsLoading(true);
              const current = iframeUrl;
              setIframeUrl('');
              setTimeout(() => setIframeUrl(current), 10);
            }}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Reload"
          >
            <svg className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        </div>

        {/* Address Bar */}
        <div className="flex-1 flex items-center bg-white border border-gray-300 rounded-full px-3 py-1 shadow-sm focus-within:ring-2 focus-within:ring-[#E95420]/30 focus-within:border-[#E95420] transition-all">
          <div className="text-gray-400 mr-2">
            <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <input 
            type="text"
            className="flex-1 bg-transparent border-none outline-none text-sm text-gray-700"
            value={urlInput}
            onChange={(e) => setUrlInput(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>

        {/* History Button */}
        <div className="relative" ref={dropdownRef}>
          <button 
            onClick={() => setIsHistoryOpen(!isHistoryOpen)}
            className={`p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors ${isHistoryOpen ? 'bg-gray-200' : ''}`}
            title="History"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>

          {/* History Dropdown */}
          {isHistoryOpen && (
            <div className="absolute right-0 mt-2 w-72 bg-white border border-gray-200 rounded-lg shadow-xl z-50 overflow-hidden py-1">
              <div className="px-3 py-2 border-b border-gray-100 flex justify-between items-center">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">Browsing History</span>
                <button 
                  onClick={clearHistory}
                  className="text-[10px] text-[#E95420] hover:underline font-medium"
                >
                  Clear All
                </button>
              </div>
              <div className="max-h-60 overflow-y-auto no-scrollbar">
                {history.length === 0 ? (
                  <div className="px-4 py-3 text-sm text-gray-400 italic">No history yet</div>
                ) : (
                  history.map((url, idx) => (
                    <button
                      key={idx}
                      onClick={() => navigateTo(url)}
                      className="w-full text-left px-4 py-2 text-sm hover:bg-gray-50 transition-colors truncate border-b border-gray-50 last:border-0"
                      title={url}
                    >
                      <div className="flex items-center space-x-2">
                        <svg className="w-3 h-3 text-gray-400 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101" />
                        </svg>
                        <span className="truncate text-gray-700">{url}</span>
                      </div>
                    </button>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        <button 
          onClick={() => navigateTo(defaultUrl)}
          className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
          title="Home"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
          </svg>
        </button>
      </div>

      {/* Security Info Bar */}
      <div className="bg-[#FFF9C4] text-[10px] px-4 py-0.5 text-[#827717] font-medium border-b border-[#FBC02D]/20 flex justify-between">
        <span>Some sites may block embedding for security. Try Wikipedia or Archive.org.</span>
        <span className="hidden sm:inline italic">Ubuntu Firefox Intelligence Core v1.0</span>
      </div>

      {/* Content Area */}
      <div className="flex-1 bg-gray-100 relative overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/80 z-10">
            <div className="flex flex-col items-center">
              <div className="w-8 h-8 border-4 border-[#E95420] border-t-transparent rounded-full animate-spin"></div>
              <span className="mt-2 text-xs font-medium text-gray-500 uppercase tracking-widest">Loading...</span>
            </div>
          </div>
        )}
        <iframe 
          src={iframeUrl}
          className="w-full h-full border-none bg-white"
          onLoad={handleLoad}
          title="Browser Content"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
        />
      </div>
    </div>
  );
};

export default Browser;

import React, { useState, useRef, useEffect } from 'react';
import { TerminalLine } from '../../types';
import { geminiService } from '../../services/geminiService';
import { marked } from 'marked';

const Terminal: React.FC = () => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Welcome to Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * AI Core:        Gemini 3 Flash' },
    { type: 'system', content: ' * Capabilities:   Full Web Grounding, Command Synthesis' },
    { type: 'system', content: '' },
    { type: 'system', content: 'Ubuntu Intelligence ready. Type your query or help.' },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [lines, isProcessing]);

  // Configure marked options if needed
  useEffect(() => {
    marked.setOptions({
      breaks: true,
      gfm: true,
    });
  }, []);

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isProcessing) return;

    const cmd = inputValue.trim();
    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console cleared. Ubuntu Intelligence standing by.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: '### Available Commands\n- **clear**: Wipes the terminal history.\n- **help**: Shows this message.\n- **whoami**: Displays current user session info.\n- **info**: System hardware and AI details.\n\nOr simply type a question about current events or technical tasks!' }
      ]);
      setIsProcessing(false);
      return;
    }

    const { text, sources } = await geminiService.processCommand(cmd);

    let fullOutput = text;
    if (sources && sources.length > 0) {
      fullOutput += "\n\n### Sources\n";
      sources.forEach(s => {
        fullOutput += `- [${s.title}](${s.uri})\n`;
      });
    }

    setLines(prev => [...prev, { type: 'output', content: fullOutput }]);
    setIsProcessing(false);
  };

  return (
    <div 
      className="h-full bg-[#300A24] text-[#FFFFFF] p-4 ubuntu-terminal overflow-y-auto no-scrollbar selection:bg-[#E95420] selection:text-white cursor-text"
      ref={scrollRef}
      onClick={() => inputRef.current?.focus()}
    >
      <div className="space-y-1">
        {lines.map((line, i) => (
          <div key={i} className="break-words">
            {line.type === 'input' && (
              <span className="flex">
                <span className="text-[#87ff5f] font-bold">ubuntu@intelligence</span>
                <span className="text-white mr-2">:~$</span>
                <span className="flex-1">{line.content}</span>
              </span>
            )}
            {line.type === 'output' && (
              <div 
                className="terminal-markdown pl-2 border-l-2 border-[#E95420]/50 mb-4 py-1 text-gray-100 text-[14px] leading-relaxed"
                dangerouslySetInnerHTML={{ __html: marked.parse(line.content) }}
              />
            )}
            {line.type === 'system' && (
              <div className="text-gray-400 opacity-60 text-xs italic">{line.content}</div>
            )}
            {line.type === 'error' && (
              <div className="text-red-400">{line.content}</div>
            )}
          </div>
        ))}
        {isProcessing && (
          <div className="flex items-center space-x-2 text-[#E95420] pb-4">
            <span className="w-1.5 h-4 bg-[#E95420] animate-pulse"></span>
            <span className="italic text-xs font-bold uppercase tracking-widest">Consulting Neural Core...</span>
          </div>
        )}
        <form onSubmit={handleCommand} className="flex mt-2">
          <span className="text-[#87ff5f] font-bold whitespace-nowrap">ubuntu@intelligence</span>
          <span className="text-white mr-2">:~$</span>
          <input
            ref={inputRef}
            autoFocus
            className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0 terminal-input"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            disabled={isProcessing}
          />
        </form>
      </div>
    </div>
  );
};

