import React, { useState, useCallback, useEffect } from 'react';
import { AppID, WindowState } from './types';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import Window from './components/Window';
import Terminal from './components/apps/Terminal';
import FileExplorer from './components/apps/FileExplorer';
import About from './components/apps/About';
import Browser from './components/apps/Browser';
import Settings from './components/apps/Settings';
import NeoBrowser from './components/apps/NeoBrowser';
import UbuntuDemo from './components/apps/UbuntuDemo';
import VLC from './components/apps/VLC';
import Orbital from './components/apps/Orbital';

const App: React.FC = () => {
  const [wallpaper, setWallpaper] = useState('https://picsum.photos/seed/ubuntu/1920/1080');
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'terminal', title: 'Terminal - Gemini Core', isOpen: true, isMaximized: false, zIndex: 10 },
    { id: 'files', title: 'File Explorer', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'browser', title: 'Web Browser', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'neo-browser', title: 'NÉO WEB-EXPLORER', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'ubuntu-demo', title: 'Ubuntu API Demo', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'vlc', title: 'VLC Media Player', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'orbital', title: 'Orbital PS4 Emulator', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'settings', title: 'Settings', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'about', title: 'About Ubuntu Intelligence', isOpen: false, isMaximized: false, zIndex: 1 },
  ]);
  const [highestZ, setHighestZ] = useState(10);
  const [notifications, setNotifications] = useState<{id: number, text: string}[]>([]);

  const addNotification = useCallback((text: string) => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, text }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const toggleApp = useCallback((id: AppID) => {
    setWindows(prev => {
      const exists = prev.find(w => w.id === id);
      const newHighestZ = highestZ + 1;
      setHighestZ(newHighestZ);

      if (exists) {
        return prev.map(w => w.id === id ? { ...w, isOpen: true, zIndex: newHighestZ } : w);
      } else {
        return [...prev, { id, title: id.charAt(0).toUpperCase() + id.slice(1), isOpen: true, isMaximized: false, zIndex: newHighestZ }];
      }
    });
  }, [highestZ]);

  const closeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const maximizeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
  };

  const focusWindow = (id: AppID) => {
    const newHighestZ = highestZ + 1;
    setHighestZ(newHighestZ);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: newHighestZ } : w));
  };

  const getActiveApp = (): AppID | undefined => {
    const openWindows = windows.filter(w => w.isOpen).sort((a, b) => b.zIndex - a.zIndex);
    return openWindows.length > 0 ? openWindows[0].id : undefined;
  };

  const getAppIcon = (id: AppID) => {
    switch (id) {
      case 'terminal': return 'https://img.icons8.com/color/48/000000/terminal.png';
      case 'files': return 'https://img.icons8.com/color/48/000000/folder-invoices.png';
      case 'browser': return 'https://img.icons8.com/color/48/000000/firefox.png';
      case 'neo-browser': return 'https://img.icons8.com/fluency/48/internet.png';
      case 'ubuntu-demo': return 'https://img.icons8.com/fluency/48/code.png';
      case 'vlc': return 'https://img.icons8.com/color/48/000000/vlc.png';
      case 'orbital': return 'https://img.icons8.com/fluency/48/controller.png';
      case 'settings': return 'https://img.icons8.com/color/48/000000/settings.png';
      case 'about': return 'https://img.icons8.com/color/48/000000/info--v1.png';
      default: return 'https://img.icons8.com/color/48/000000/ubuntu.png';
    }
  };

  useEffect(() => {
    addNotification("System Intelligence initialized.");
  }, [addNotification]);

  return (
    <div 
        className="h-screen w-screen flex flex-col overflow-hidden transition-all duration-1000 ease-in-out"
        style={{ 
            backgroundImage: `url('${wallpaper}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
        }}
    >
      <TopBar />

      <div className="flex-1 flex overflow-hidden">
        <Sidebar onAppClick={toggleApp} activeApp={getActiveApp()} />

        <main className="flex-1 relative overflow-hidden">
          {windows.map(window => (
            <Window
              key={window.id}
              id={window.id}
              title={window.title}
              isOpen={window.isOpen}
              isMaximized={window.isMaximized}
              zIndex={window.zIndex}
              onClose={() => closeWindow(window.id)}
              onMaximize={() => maximizeWindow(window.id)}
              onFocus={() => focusWindow(window.id)}
              icon={getAppIcon(window.id)}
            >
              {window.id === 'terminal' && <Terminal />}
              {window.id === 'files' && <FileExplorer />}
              {window.id === 'about' && <About />}
              {window.id === 'browser' && <Browser />}
              {window.id === 'neo-browser' && <NeoBrowser />}
              {window.id === 'ubuntu-demo' && <UbuntuDemo />}
              {window.id === 'vlc' && <VLC />}
              {window.id === 'orbital' && <Orbital />}
              {window.id === 'settings' && (
                <Settings 
                    currentWallpaper={wallpaper} 
                    onWallpaperChange={(url) => {
                        setWallpaper(url);
                        addNotification("Desktop background updated.");
                    }} 
                />
              )}
            </Window>
          ))}

          {/* Notifications Area */}
          <div className="absolute top-4 right-4 z-[100] flex flex-col space-y-2 pointer-events-none">
            {notifications.map(n => (
              <div 
                key={n.id} 
                className="bg-black/80 backdrop-blur-md text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl animate-in fade-in slide-in-from-right-full duration-300 pointer-events-auto"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-[#E95420] rounded-full flex items-center justify-center text-[10px] font-bold">!</div>
                  <span className="text-sm font-medium">{n.text}</span>
                </div>
              </div>
            ))}
          </div>

          <div className="absolute inset-0 z-0" onContextMenu={(e) => e.preventDefault()}>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

