import React, { useState, useRef, useEffect, useMemo } from 'react';
import { TerminalLine } from '../../types';
import { geminiService } from '../../services/geminiService';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';
import { Virtuoso, VirtuosoHandle } from 'react-virtuoso';

const commands = ['clear', 'help', 'whoami', 'info'];

const CopyButton: React.FC<{ text: string }> = ({ text }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy text: ', err);
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={`absolute top-2 right-2 p-1.5 rounded-md transition-all duration-200 opacity-0 group-hover:opacity-100 ${
        copied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
      }`}
      title="Copy to clipboard"
    >
      {copied ? (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
        </svg>
      ) : (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
        </svg>
      )}
    </button>
  );
};

const markdownComponents = {
  code({ node, inline, className, children, ...props }: any) {
    const match = /language-(\w+)/.exec(className || '');
    return !inline && match ? (
      <SyntaxHighlighter
        style={atomDark}
        language={match[1]}
        PreTag="div"
        {...props}
      >
        {String(children).replace(/\n$/, '')}
      </SyntaxHighlighter>
    ) : (
      <code className={className} {...props}>
        {children}
      </code>
    );
  },
};

const Footer: React.FC<{ context: any }> = ({ context }) => {
  const { 
    inputValue, 
    handleInputChange, 
    handleKeyDown, 
    handleCommand, 
    isProcessing, 
    suggestions, 
    inputRef 
  } = context;

  return (
    <div className="pb-4">
      {isProcessing && (
        <div className="flex items-center space-x-2 text-[#E95420] pb-4">
          <span className="w-1.5 h-4 bg-[#E95420] animate-pulse"></span>
          <span className="italic text-xs font-bold uppercase tracking-widest">Consulting Neural Core...</span>
        </div>
      )}
      <form onSubmit={handleCommand} className="flex mt-2">
        <span className="text-[#87ff5f] font-bold whitespace-nowrap">ubuntu@intelligence</span>
        <span className="text-white mr-2">:~$</span>
        <input
          ref={inputRef}
          autoFocus
          className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0 terminal-input"
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          disabled={isProcessing}
        />
      </form>
      {suggestions.length > 0 && (
        <div className="mt-2 p-2 rounded-md bg-[#25081A] border border-white/10 w-full md:w-auto md:max-w-xl">
          <div className="flex flex-wrap gap-x-6 gap-y-1">
            {suggestions.map((s: string) => (
              <span key={s} className="text-gray-300">{s}</span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const Terminal: React.FC = () => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Welcome to Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * AI Core:        Gemini 3 Flash' },
    { type: 'system', content: ' * Capabilities:   Full Web Grounding, Command Synthesis' },
    { type: 'system', content: '' },
    { type: 'system', content: 'Ubuntu Intelligence ready. Type `help` for commands or press `Tab` to autocomplete.' },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [allCopied, setAllCopied] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const virtuosoRef = useRef<VirtuosoHandle>(null);

  const handleCopyAll = async () => {
    const allText = lines.map(line => {
      switch(line.type) {
        case 'input':
          return `ubuntu@intelligence:~$ ${line.content}`;
        case 'output':
        case 'system':
        case 'error':
          return line.content;
        default:
          return '';
      }
    }).join('\n\n');

    try {
      await navigator.clipboard.writeText(allText);
      setAllCopied(true);
      setTimeout(() => setAllCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy all text: ', err);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
    if (suggestions.length > 0) {
      setSuggestions([]);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const currentInput = inputValue.trim();
      if (!currentInput) return;

      const matches = commands.filter(cmd => cmd.startsWith(currentInput));
      if (matches.length === 1) {
        setInputValue(matches[0] + ' ');
        setSuggestions([]);
      } else if (matches.length > 1) {
        setSuggestions(matches);
      }
    }
  };

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isProcessing) return;
    setSuggestions([]);

    const cmd = inputValue.trim();
    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console cleared. Ubuntu Intelligence standing by.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: '### Ubuntu Intelligence Help\n- **clear**: Wipes the terminal history.\n- **help**: Shows this message.\n- **whoami**: Displays current user session info.\n- **info**: System hardware and AI details.\n\nType any other query to consult the Gemini AI core. Use `Tab` for command autocompletion.' }
      ]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'whoami') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: '**User:** `ubuntu`\n**Hostname:** `intelligence-vm`\n**Shell:** `/bin/gemini-sh`' }
      ]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'info') {
        setLines(prev => [
            ...prev,
            { type: 'output', content: '**System:** `Ubuntu Intelligence v1.0`\n**Kernel:** `6.8.0-generic x86_64`\n**AI Core:** `Gemini 3 Flash`\n**Status:** `All systems nominal.`' }
        ]);
        setIsProcessing(false);
        return;
    }

    const { text, sources } = await geminiService.processCommand(cmd);

    let fullOutput = text;
    if (sources && sources.length > 0) {
      fullOutput += "\n\n### Sources\n";
      sources.forEach(s => {
        fullOutput += `- [${s.title}](${s.uri})\n`;
      });
    }

    setLines(prev => [...prev, { type: 'output', content: fullOutput }]);
    setIsProcessing(false);
  };

  const contextValue = useMemo(() => ({
    inputValue,
    handleInputChange,
    handleKeyDown,
    handleCommand,
    isProcessing,
    suggestions,
    inputRef
  }), [inputValue, isProcessing, suggestions]);

  return (
    <div 
      className="h-full bg-[#300A24] text-[#FFFFFF] p-4 ubuntu-terminal selection:bg-[#E95420] selection:text-white cursor-text relative"
      onClick={() => inputRef.current?.focus()}
    >
      <button
        onClick={handleCopyAll}
        className={`absolute top-2 right-12 p-1.5 rounded-md transition-all duration-200 z-10 ${
          allCopied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
        }`}
        title="Copy all to clipboard"
      >
        {allCopied ? (
          <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        ) : (
          <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
          </svg>
        )}
      </button>

      <Virtuoso
        ref={virtuosoRef}
        style={{ height: '100%' }}
        data={lines}
        followOutput="auto"
        initialTopMostItemIndex={lines.length - 1}
        context={contextValue}
        components={{ Footer }}
        itemContent={(index, line) => (
          <div className="break-words mb-1">
            {line.type === 'input' && (
              <span className="flex">
                <span className="text-[#87ff5f] font-bold">ubuntu@intelligence</span>
                <span className="text-white mr-2">:~$</span>
                <span className="flex-1">{line.content}</span>
              </span>
            )}
            {line.type === 'output' && (
              <div className="relative group mb-4">
                <ReactMarkdown
                  className="terminal-markdown pl-2 border-l-2 border-[#E95420]/50 py-1 text-gray-100 text-[14px] leading-relaxed"
                  components={markdownComponents}
                  remarkPlugins={[remarkGfm]}
                >
                  {line.content}
                </ReactMarkdown>
                <CopyButton text={line.content} />
              </div>
            )}
            {line.type === 'system' && (
              <div className="text-gray-400 opacity-60 text-xs italic">{line.content}</div>
            )}
            {line.type === 'error' && (
              <div className="text-red-400">{line.content}</div>
            )}
          </div>
        )}
      />
    </div>
  );
};

export default Terminal;

