import { GoogleGenAI } from "@google/genai";

export interface GeminiResponse {
  text: string;
  sources?: { title: string; uri: string }[];
}

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async processCommand(command: string): Promise<GeminiResponse> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: command,
        config: {
          systemInstruction: `You are 'Ubuntu Intelligence', a highly sophisticated AI assistant integrated into a web-based Ubuntu 24.04 environment. 
          Users interact via terminal.
          - Use terminal-friendly formatting (monospaced tables, lists).
          - If the user asks about current events, use your search tool.
          - Maintain a professional yet helpful Ubuntu-centric persona.
          - Always provide source URLs if you use Google Search grounding.`,
          tools: [{ googleSearch: {} }],
          temperature: 0.7,
        },
      });

      const text = response.text || "No response received from the system.";
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const sources = chunks?.map(chunk => ({
        title: chunk.web?.title || 'Source',
        uri: chunk.web?.uri || ''
      })).filter(s => s.uri !== '') || [];

      return { text, sources };
    } catch (error: unknown) {
      console.error("Gemini API Error:", error);

      let errorMessage = `Error: An unknown system failure occurred.`;
      const errorString = error instanceof Error ? error.message : JSON.stringify(error);

      if (errorString.toLowerCase().includes('permission') || errorString.toLowerCase().includes('api key')) {
        errorMessage = `**System Alert: Gemini API Permission Denied.**\n\nThis usually means the API key is missing, invalid, or not configured correctly in the environment.\n\nPlease ensure \`process.env.API_KEY\` is set up with a valid key that has the Gemini API enabled.`;
      } else {
        errorMessage = `**System Error:** An unexpected issue occurred.\n\n\`\`\`\n${errorString}\n\`\`\``;
      }

      return { 
        text: errorMessage,
        sources: [] 
      };
    }
  }
}

