import React, { useState, useCallback, useEffect } from 'react';
import { AppID, WindowState } from './types';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import Window from './components/Window';
import Terminal from './components/apps/Terminal';
import FileExplorer from './components/apps/FileExplorer';
import About from './components/apps/About';
import Browser from './components/apps/Browser';
import Settings from './components/apps/Settings';
import NeoBrowser from './components/apps/NeoBrowser';
import UbuntuDemo from './components/apps/UbuntuDemo';
import VLC from './components/apps/VLC';
import Orbital from './components/apps/Orbital';

const App: React.FC = () => {
  const [wallpaper, setWallpaper] = useState('https://picsum.photos/seed/ubuntu/1920/1080');
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'terminal', title: 'Terminal - Gemini Core', isOpen: true, isMaximized: false, zIndex: 10 },
    { id: 'files', title: 'File Explorer', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'browser', title: 'Web Browser', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'neo-browser', title: 'NÉO WEB-EXPLORER', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'ubuntu-demo', title: 'Ubuntu API Demo', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'vlc', title: 'VLC Media Player', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'orbital', title: 'Orbital PS4 Emulator', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'settings', title: 'Settings', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'about', title: 'About Ubuntu Intelligence', isOpen: false, isMaximized: false, zIndex: 1 },
  ]);
  const [highestZ, setHighestZ] = useState(10);
  const [notifications, setNotifications] = useState<{id: number, text: string}[]>([]);

  const addNotification = useCallback((text: string) => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, text }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const toggleApp = useCallback((id: AppID) => {
    setWindows(prev => {
      const exists = prev.find(w => w.id === id);
      const newHighestZ = highestZ + 1;
      setHighestZ(newHighestZ);

      if (exists) {
        return prev.map(w => w.id === id ? { ...w, isOpen: true, zIndex: newHighestZ } : w);
      } else {
        return [...prev, { id, title: id.charAt(0).toUpperCase() + id.slice(1), isOpen: true, isMaximized: false, zIndex: newHighestZ }];
      }
    });
  }, [highestZ]);

  const closeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const maximizeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
  };

  const focusWindow = (id: AppID) => {
    const newHighestZ = highestZ + 1;
    setHighestZ(newHighestZ);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: newHighestZ } : w));
  };

  const getActiveApp = (): AppID | undefined => {
    const openWindows = windows.filter(w => w.isOpen).sort((a, b) => b.zIndex - a.zIndex);
    return openWindows.length > 0 ? openWindows[0].id : undefined;
  };

  const getAppIcon = (id: AppID) => {
    switch (id) {
      case 'terminal': return 'https://img.icons8.com/color/48/000000/terminal.png';
      case 'files': return 'https://img.icons8.com/color/48/000000/folder-invoices.png';
      case 'browser': return 'https://img.icons8.com/color/48/000000/firefox.png';
      case 'neo-browser': return 'https://img.icons8.com/fluency/48/internet.png';
      case 'ubuntu-demo': return 'https://img.icons8.com/fluency/48/code.png';
      case 'vlc': return 'https://img.icons8.com/color/48/000000/vlc.png';
      case 'orbital': return 'https://img.icons8.com/fluency/48/controller.png';
      case 'settings': return 'https://img.icons8.com/color/48/000000/settings.png';
      case 'about': return 'https://img.icons8.com/color/48/000000/info--v1.png';
      default: return 'https://img.icons8.com/color/48/000000/ubuntu.png';
    }
  };

  useEffect(() => {
    addNotification("System Intelligence initialized.");
  }, [addNotification]);

  return (
    <div 
        className="h-screen w-screen flex flex-col overflow-hidden transition-all duration-1000 ease-in-out"
        style={{ 
            backgroundImage: `url('${wallpaper}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
        }}
    >
      <TopBar />

      <div className="flex-1 flex overflow-hidden">
        <Sidebar onAppClick={toggleApp} activeApp={getActiveApp()} />

        <main className="flex-1 relative overflow-hidden">
          {windows.map(window => (
            <Window
              key={window.id}
              id={window.id}
              title={window.title}
              isOpen={window.isOpen}
              isMaximized={window.isMaximized}
              zIndex={window.zIndex}
              onClose={() => closeWindow(window.id)}
              onMaximize={() => maximizeWindow(window.id)}
              onFocus={() => focusWindow(window.id)}
              icon={getAppIcon(window.id)}
            >
              {window.id === 'terminal' && <Terminal onAppOpen={toggleApp} addNotification={addNotification} />}
              {window.id === 'files' && <FileExplorer />}
              {window.id === 'about' && <About />}
              {window.id === 'browser' && <Browser />}
              {window.id === 'neo-browser' && <NeoBrowser />}
              {window.id === 'ubuntu-demo' && <UbuntuDemo />}
              {window.id === 'vlc' && <VLC />}
              {window.id === 'orbital' && <Orbital />}
              {window.id === 'settings' && (
                <Settings 
                    currentWallpaper={wallpaper} 
                    onWallpaperChange={(url) => {
                        setWallpaper(url);
                        addNotification("Desktop background updated.");
                    }} 
                />
              )}
            </Window>
          ))}

          {/* Notifications Area */}
          <div className="absolute top-4 right-4 z-[100] flex flex-col space-y-2 pointer-events-none">
            {notifications.map(n => (
              <div 
                key={n.id} 
                className="bg-black/80 backdrop-blur-md text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl animate-in fade-in slide-in-from-right-full duration-300 pointer-events-auto"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-[#E95420] rounded-full flex items-center justify-center text-[10px] font-bold">!</div>
                  <span className="text-sm font-medium">{n.text}</span>
                </div>
              </div>
            ))}
          </div>

          <div className="absolute inset-0 z-0" onContextMenu={(e) => e.preventDefault()}>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { TerminalLine, AppID } from '../../types';
import { geminiService } from '../../services/geminiService';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';
import { Virtuoso, VirtuosoHandle } from 'react-virtuoso';

const commands = ['clear', 'help', 'whoami', 'info', 'pkg', 'sudo'];

const packageMap: Record<string, AppID> = {
  'file-explorer': 'files',
  'firefox': 'browser',
  'neo-browser': 'neo-browser',
  'ubuntu-demo': 'ubuntu-demo',
  'vlc': 'vlc',
  'orbital-ps4': 'orbital',
  'settings': 'settings',
  'about-ubuntu': 'about',
};

interface TerminalProps {
  onAppOpen: (id: AppID) => void;
  addNotification: (text: string) => void;
}

const CopyButton: React.FC<{ text: string }> = ({ text }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy text: ', err);
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={`absolute top-2 right-2 p-1.5 rounded-md transition-all duration-200 opacity-0 group-hover:opacity-100 ${
        copied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
      }`}
      title="Copy to clipboard"
    >
      {copied ? (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
        </svg>
      ) : (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 S0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
        </svg>
      )}
    </button>
  );
};

const markdownComponents = {
  code({ node, inline, className, children, ...props }: any) {
    const match = /language-(\w+)/.exec(className || '');
    return !inline && match ? (
      <SyntaxHighlighter
        style={atomDark}
        language={match[1]}
        PreTag="div"
        {...props}
      >
        {String(children).replace(/\n$/, '')}
      </SyntaxHighlighter>
    ) : (
      <code className={className} {...props}>
        {children}
      </code>
    );
  },
};

const Footer: React.FC<{ context: any }> = ({ context }) => {
  const { 
    inputValue, 
    handleInputChange, 
    handleKeyDown, 
    handleCommand, 
    isProcessing, 
    suggestions, 
    setInputRef
  } = context;

  return (
    <div className="pb-4">
      {isProcessing && (
        <div className="flex items-center space-x-2 text-[#E95420] pb-4">
          <span className="w-1.5 h-4 bg-[#E95420] animate-pulse"></span>
          <span className="italic text-xs font-bold uppercase tracking-widest">Consulting Neural Core...</span>
        </div>
      )}
      <form onSubmit={handleCommand} className="flex mt-2">
        <span className="text-[#87ff5f] font-bold whitespace-nowrap">ubuntu@intelligence</span>
        <span className="text-white mr-2">:~$</span>
        <input
          ref={setInputRef}
          autoFocus
          className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0 terminal-input"
          value={inputValue}
          onChange={handleInputChange}
          onKeyDown={handleKeyDown}
          disabled={isProcessing}
        />
      </form>
      {suggestions.length > 0 && (
        <div className="mt-2 p-2 rounded-md bg-[#25081A] border border-white/10 w-full md:w-auto md:max-w-xl">
          <div className="flex flex-wrap gap-x-6 gap-y-1">
            {suggestions.map((s: string) => (
              <span key={s} className="text-gray-300">{s}</span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const Terminal: React.FC<TerminalProps> = ({ onAppOpen, addNotification }) => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Welcome to Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * AI Core:        Gemini 3 Flash' },
    { type: 'system', content: ' * Capabilities:   Full Web Grounding, Command Synthesis' },
    { type: 'system', content: '' },
    { type: 'system', content: 'Ubuntu Intelligence ready. Type `help` for commands or press `Tab` to autocomplete.' },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [allCopied, setAllCopied] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement | null>(null);
  const virtuosoRef = useRef<VirtuosoHandle>(null);

  const handleCopyAll = async () => {
    const allText = lines.map(line => {
      switch(line.type) {
        case 'input':
          return `ubuntu@intelligence:~$ ${line.content}`;
        case 'output':
        case 'system':
        case 'error':
          return line.content;
        default:
          return '';
      }
    }).join('\n\n');

    try {
      await navigator.clipboard.writeText(allText);
      setAllCopied(true);
      setTimeout(() => setAllCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy all text: ', err);
    }
  };

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
    if (suggestions.length > 0) {
      setSuggestions([]);
    }
  }, [suggestions.length]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const currentInput = inputValue.trim();
      if (!currentInput) return;

      const matches = commands.filter(cmd => cmd.startsWith(currentInput));
      if (matches.length === 1) {
        setInputValue(matches[0] + ' ');
        setSuggestions([]);
      } else if (matches.length > 1) {
        setSuggestions(matches);
      }
    }
  }, [inputValue]);

  const simulateInstall = useCallback(async (pkgName: string, appId: AppID) => {
    const addLine = (content: string, delay: number) => {
        return new Promise(resolve => setTimeout(() => {
            setLines(prev => [...prev, { type: 'system', content }]);
            resolve(true);
        }, delay));
    };

    await addLine('Reading package lists... Done', 300);
    await addLine('Building dependency tree... Done', 500);
    await addLine(`The following NEW packages will be installed: ${pkgName}`, 200);
    await addLine(`Unpacking ${pkgName}...`, 800);
    await addLine(`Setting up ${pkgName}...`, 1000);
    await addLine(`Installation complete. Launching application...`, 400);

    onAppOpen(appId);
    setIsProcessing(false);
  }, [onAppOpen]);

  const simulateUpdate = useCallback(async () => {
    const addLine = (content: string, delay: number) => {
        return new Promise(resolve => setTimeout(() => {
            setLines(prev => [...prev, { type: 'system', content }]);
            resolve(true);
        }, delay));
    };

    await addLine('Hit:1 http://archive.ubuntu.com/ubuntu noble InRelease', 300);
    await addLine('Get:2 http://security.ubuntu.com/ubuntu noble-security InRelease [120 kB]', 500);
    await addLine('Reading package lists... Done', 400);
    await addLine('Building dependency tree... Done', 600);
    await addLine('Calculating upgrade... Done', 300);
    await addLine('The following packages will be upgraded:', 200);
    await addLine('  ubuntu-intelligence-core (1.0.0 -> 1.1.0)', 150);
    await addLine('  gemini-runtime-libs (3.1.2 -> 3.2.0)', 150);
    await addLine('2 upgraded, 0 newly installed, 0 to remove and 0 not upgraded.', 200);
    await addLine('Need to get 15.2 MB of archives.', 200);
    await addLine('After this operation, 2.5 MB of additional disk space will be used.', 200);
    await addLine('Get:1 http://archive.ubuntu.com/ubuntu noble/main amd64 ubuntu-intelligence-core 1.1.0 [12.1 MB]', 1200);
    await addLine('Get:2 http://archive.ubuntu.com/ubuntu noble/main amd64 gemini-runtime-libs 3.2.0 [3.1 MB]', 500);
    await addLine('Fetched 15.2 MB in 1.7s (8.9 MB/s)', 100);
    await addLine('Setting up ubuntu-intelligence-core (1.1.0)...', 800);
    await addLine('Setting up gemini-runtime-libs (3.2.0)...', 600);
    await addLine('System update complete. Restart not required.', 400);

    addNotification("System is up to date.");
    setIsProcessing(false);
  }, [addNotification]);

  const handleCommand = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isProcessing) return;
    setSuggestions([]);

    const cmd = inputValue.trim();
    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console cleared. Ubuntu Intelligence standing by.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'sudo apt update && sudo apt upgrade') {
      await simulateUpdate();
      return;
    }

    if (cmd.startsWith('pkg install')) {
      const parts = cmd.split(' ');
      if (parts.length < 3 || !parts[2]) {
        setLines(prev => [...prev, { type: 'error', content: 'Usage: pkg install <package_name>' }]);
        setIsProcessing(false);
        return;
      }
      const pkgName = parts[2];
      const appId = packageMap[pkgName];
      if (appId) {
        await simulateInstall(pkgName, appId);
      } else {
        setLines(prev => [...prev, { type: 'error', content: `E: Unable to locate package ${pkgName}` }]);
        setIsProcessing(false);
      }
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: '### Ubuntu Intelligence Help\n- **clear**: Wipes the terminal history.\n- **help**: Shows this message.\n- **whoami**: Displays current user session info.\n- **info**: System hardware and AI details.\n- **pkg install [package]**: Simulates installing and launching an app.\n- **sudo apt update && sudo apt upgrade**: Simulates a system update.\n\nType any other query to consult the Gemini AI core.' }
      ]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'whoami') {
      setLines(prev => [
        ...prev,
        { type: 'output', content: '**User:** `ubuntu`\n**Hostname:** `intelligence-vm`\n**Shell:** `/bin/gemini-sh`' }
      ]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'info') {
        setLines(prev => [
            ...prev,
            { type: 'output', content: '**System:** `Ubuntu Intelligence v1.0`\n**Kernel:** `6.8.0-generic x86_64`\n**AI Core:** `Gemini 3 Flash`\n**Status:** `All systems nominal.`' }
        ]);
        setIsProcessing(false);
        return;
    }

    const { text, sources } = await geminiService.processCommand(cmd);

    let fullOutput = text;
    if (sources && sources.length > 0) {
      fullOutput += "\n\n### Sources\n";
      sources.forEach(s => {
        fullOutput += `- [${s.title}](${s.uri})\n`;
      });
    }

    setLines(prev => [...prev, { type: 'output', content: fullOutput }]);
    setIsProcessing(false);
  }, [inputValue, isProcessing, simulateInstall, simulateUpdate]);

  const setInputRef = useCallback((element: HTMLInputElement | null) => {
    inputRef.current = element;
  }, []);

  const contextValue = useMemo(() => ({
    inputValue,
    handleInputChange,
    handleKeyDown,
    handleCommand,
    isProcessing,
    suggestions,
    setInputRef
  }), [
    inputValue,
    handleInputChange,
    handleKeyDown,
    handleCommand,
    isProcessing,
    suggestions,
    setInputRef
  ]);

  return (
    <div 
      className="h-full bg-[#300A24] text-[#FFFFFF] p-4 ubuntu-terminal selection:bg-[#E95420] selection:text-white cursor-text relative"
      onClick={() => inputRef.current?.focus()}
    >
      <button
        onClick={handleCopyAll}
        className={`absolute top-2 right-12 p-1.5 rounded-md transition-all duration-200 z-10 ${
          allCopied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
        }`}
        title="Copy all to clipboard"
      >
        {allCopied ? (
          <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
          </svg>
        ) : (
          <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
          </svg>
        )}
      </button>

      <Virtuoso
        ref={virtuosoRef}
        style={{ height: '100%' }}
        data={lines}
        followOutput="auto"
        initialTopMostItemIndex={lines.length - 1}
        context={contextValue}
        components={{ Footer }}
        itemContent={(index, line) => (
          <div className="break-words mb-1">
            {line.type === 'input' && (
              <span className="flex">
                <span className="text-[#87ff5f] font-bold">ubuntu@intelligence</span>
                <span className="text-white mr-2">:~$</span>
                <span className="flex-1">{line.content}</span>
              </span>
            )}
            {line.type === 'output' && (
              <div className="relative group mb-4">
                <ReactMarkdown
                  className="terminal-markdown pl-2 border-l-2 border-[#E95420]/50 py-1 text-gray-100 text-[14px] leading-relaxed"
                  components={markdownComponents}
                  remarkPlugins={[remarkGfm]}
                >
                  {line.content}
                </ReactMarkdown>
                <CopyButton text={line.content} />
              </div>
            )}
            {line.type === 'system' && (
              <div className="text-gray-400 opacity-60 text-xs italic">{line.content}</div>
            )}
            {line.type === 'error' && (
              <div className="text-red-400">{line.content}</div>
            )}
          </div>
        )}
      />
    </div>
  );
};

export default Terminal;

