import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';

interface Message {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { 
      role: 'model', 
      content: "Bonjour ! Je suis l'assistant IA d'Ubuntu Intelligence. Comment puis-je vous aider aujourd'hui ?", 
      timestamp: new Date() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatSession = useRef<Chat | null>(null);

  // Initialize Chat Session
  useEffect(() => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    chatSession.current = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "Tu es 'Ubuntu Intelligence Chat', un assistant IA souverain intégré dans un environnement Ubuntu 24.04. Tu es serviable, technique et précis. Utilise le formatage Markdown pour tes réponses.",
        temperature: 0.8,
      },
    });
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping || !chatSession.current) return;

    const userMessage: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      const result = await chatSession.current.sendMessageStream({ message: input });

      let fullResponse = '';
      const aiMessage: Message = {
        role: 'model',
        content: '',
        timestamp: new Date()
      };

      setMessages(prev => [...prev, aiMessage]);

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        const chunkText = c.text || "";
        fullResponse += chunkText;

        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1] = {
            ...newMessages[newMessages.length - 1],
            content: fullResponse
          };
          return newMessages;
        });
      }
    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, {
        role: 'model',
        content: "Erreur système : Impossible de contacter le noyau neuronal. Veuillez vérifier votre connexion.",
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const clearChat = () => {
    setMessages([{ 
      role: 'model', 
      content: "Session réinitialisée. En quoi puis-je vous être utile ?", 
      timestamp: new Date() 
    }]);
    // Note: To truly reset the Gemini Chat session object, we'd recreate it, 
    // but clearing the UI history is sufficient for this experience.
  };

  const markdownComponents = {
    code({ node, inline, className, children, ...props }: any) {
      const match = /language-(\w+)/.exec(className || '');
      return !inline && match ? (
        <SyntaxHighlighter
          style={atomDark}
          language={match[1]}
          PreTag="div"
          {...props}
        >
          {String(children).replace(/\n$/, '')}
        </SyntaxHighlighter>
      ) : (
        <code className="bg-black/30 px-1 rounded text-orange-400 font-mono text-sm" {...props}>
          {children}
        </code>
      );
    },
  };

  return (
    <div className="h-full flex flex-col bg-[#2D2D2D] text-gray-100 overflow-hidden font-sans">
      {/* Header Info */}
      <div className="bg-black/20 p-3 border-b border-white/5 flex justify-between items-center shrink-0">
        <div className="flex items-center space-x-2">
          <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
          <span className="text-xs font-bold uppercase tracking-widest text-white/60">Intelligence Core v3.0</span>
        </div>
        <button 
          onClick={clearChat}
          className="text-[10px] uppercase font-bold text-gray-400 hover:text-[#E95420] transition-colors"
        >
          Effacer la discussion
        </button>
      </div>

      {/* Message Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar">
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
          >
            <div className={`max-w-[85%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-4 rounded-2xl shadow-lg relative ${
                  msg.role === 'user' 
                    ? 'bg-[#772953] text-white rounded-tr-none' 
                    : 'bg-[#3D3D3D] text-gray-100 border border-white/5 rounded-tl-none'
                }`}
              >
                <div className="terminal-markdown prose prose-invert prose-sm max-w-none">
                  <ReactMarkdown components={markdownComponents} remarkPlugins={[remarkGfm]}>
                    {msg.content}
                  </ReactMarkdown>
                </div>
              </div>
              <span className="text-[10px] mt-1 text-white/30 font-medium">
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-[#3D3D3D] p-3 rounded-2xl rounded-tl-none border border-white/5 flex items-center space-x-2">
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce"></span>
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce [animation-delay:0.4s]"></span>
              <span className="text-xs text-white/40 italic pl-2">Système en réflexion...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-black/20 border-t border-white/5 shrink-0">
        <form onSubmit={handleSend} className="flex items-center space-x-3 bg-[#3D3D3D] rounded-xl p-1 border border-white/10 focus-within:border-[#E95420] transition-colors shadow-inner">
          <input
            type="text"
            className="flex-1 bg-transparent border-none outline-none px-4 py-2 text-sm text-white placeholder-white/30"
            placeholder="Posez votre question à l'intelligence centrale..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isTyping}
          />
          <button
            type="submit"
            disabled={!input.trim() || isTyping}
            className={`p-2 rounded-lg transition-all ${
              !input.trim() || isTyping 
                ? 'text-white/20' 
                : 'text-white bg-[#E95420] hover:bg-[#d94410] shadow-lg shadow-orange-900/20'
            }`}
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </form>
        <div className="mt-2 text-[9px] text-center text-white/20 uppercase tracking-[2px] font-bold">
          Gemini 3 Flash Powered Neural Interface
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState, useCallback, useEffect } from 'react';
import { AppID, WindowState } from './types';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import Window from './components/Window';
import GlobalSearch from './components/GlobalSearch';
import Terminal from './components/apps/Terminal';
import FileExplorer from './components/apps/FileExplorer';
import About from './components/apps/About';
import Browser from './components/apps/Browser';
import Settings from './components/apps/Settings';
import NeoBrowser from './components/apps/NeoBrowser';
import UbuntuDemo from './components/apps/UbuntuDemo';
import VLC from './components/apps/VLC';
import Orbital from './components/apps/Orbital';
import AIChat from './components/apps/AIChat';

const App: React.FC = () => {
  const [wallpaper, setWallpaper] = useState('https://picsum.photos/seed/ubuntu/1920/1080');
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'terminal', title: 'Terminal - Gemini Core', isOpen: true, isMaximized: false, zIndex: 10 },
    { id: 'ai-chat', title: 'AI Chat - Neural Assistant', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'files', title: 'File Explorer', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'browser', title: 'Web Browser', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'neo-browser', title: 'NÉO WEB-EXPLORER', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'ubuntu-demo', title: 'Ubuntu API Demo', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'vlc', title: 'VLC Media Player', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'orbital', title: 'Orbital PS4 Emulator', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'settings', title: 'Settings', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'about', title: 'About Ubuntu Intelligence', isOpen: false, isMaximized: false, zIndex: 1 },
  ]);
  const [highestZ, setHighestZ] = useState(10);
  const [notifications, setNotifications] = useState<{id: number, text: string}[]>([]);

  const addNotification = useCallback((text: string) => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, text }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const toggleApp = useCallback((id: AppID) => {
    setWindows(prev => {
      const exists = prev.find(w => w.id === id);
      const newHighestZ = highestZ + 1;
      setHighestZ(newHighestZ);

      if (exists) {
        return prev.map(w => w.id === id ? { ...w, isOpen: true, zIndex: newHighestZ } : w);
      } else {
        return [...prev, { id, title: id.charAt(0).toUpperCase() + id.slice(1), isOpen: true, isMaximized: false, zIndex: newHighestZ }];
      }
    });
  }, [highestZ]);

  const closeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const maximizeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
  };

  const focusWindow = (id: AppID) => {
    const newHighestZ = highestZ + 1;
    setHighestZ(newHighestZ);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: newHighestZ } : w));
  };

  const getActiveApp = (): AppID | undefined => {
    const openWindows = windows.filter(w => w.isOpen).sort((a, b) => b.zIndex - a.zIndex);
    return openWindows.length > 0 ? openWindows[0].id : undefined;
  };

  const getAppIcon = (id: AppID) => {
    switch (id) {
      case 'terminal': return 'https://img.icons8.com/color/48/000000/terminal.png';
      case 'ai-chat': return 'https://img.icons8.com/fluency/48/robot-2.png';
      case 'files': return 'https://img.icons8.com/color/48/000000/folder-invoices.png';
      case 'browser': return 'https://img.icons8.com/color/48/000000/firefox.png';
      case 'neo-browser': return 'https://img.icons8.com/fluency/48/internet.png';
      case 'ubuntu-demo': return 'https://img.icons8.com/fluency/48/code.png';
      case 'vlc': return 'https://img.icons8.com/color/48/000000/vlc.png';
      case 'orbital': return 'https://img.icons8.com/fluency/48/controller.png';
      case 'settings': return 'https://img.icons8.com/color/48/000000/settings.png';
      case 'about': return 'https://img.icons8.com/color/48/000000/info--v1.png';
      default: return 'https://img.icons8.com/color/48/000000/ubuntu.png';
    }
  };

  useEffect(() => {
    const handleGlobalShortcuts = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'f') {
        e.preventDefault();
        setIsSearchOpen(prev => !prev);
      }
      if (e.key === 'Escape' && isSearchOpen) {
        setIsSearchOpen(false);
      }
    };

    window.addEventListener('keydown', handleGlobalShortcuts);
    return () => window.removeEventListener('keydown', handleGlobalShortcuts);
  }, [isSearchOpen]);

  useEffect(() => {
    addNotification("System Intelligence initialized. AI Chat is available.");
  }, [addNotification]);

  return (
    <div 
        className="h-screen w-screen flex flex-col overflow-hidden transition-all duration-1000 ease-in-out"
        style={{ 
            backgroundImage: `url('${wallpaper}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
        }}
    >
      <TopBar onSearchClick={() => setIsSearchOpen(true)} />

      <div className="flex-1 flex overflow-hidden">
        <Sidebar onAppClick={toggleApp} activeApp={getActiveApp()} />

        <main className="flex-1 relative overflow-hidden">
          {windows.map(window => (
            <Window
              key={window.id}
              id={window.id}
              title={window.title}
              isOpen={window.isOpen}
              isMaximized={window.isMaximized}
              zIndex={window.zIndex}
              onClose={() => closeWindow(window.id)}
              onMaximize={() => maximizeWindow(window.id)}
              onFocus={() => focusWindow(window.id)}
              icon={getAppIcon(window.id)}
            >
              {window.id === 'terminal' && <Terminal onAppOpen={toggleApp} addNotification={addNotification} />}
              {window.id === 'ai-chat' && <AIChat />}
              {window.id === 'files' && <FileExplorer />}
              {window.id === 'about' && <About />}
              {window.id === 'browser' && <Browser />}
              {window.id === 'neo-browser' && <NeoBrowser />}
              {window.id === 'ubuntu-demo' && <UbuntuDemo />}
              {window.id === 'vlc' && <VLC />}
              {window.id === 'orbital' && <Orbital />}
              {window.id === 'settings' && (
                <Settings 
                    currentWallpaper={wallpaper} 
                    onWallpaperChange={(url) => {
                        setWallpaper(url);
                        addNotification("Desktop background updated.");
                    }} 
                />
              )}
            </Window>
          ))}

          <GlobalSearch 
            isOpen={isSearchOpen} 
            onClose={() => setIsSearchOpen(false)} 
            onSelect={toggleApp} 
          />

          {/* Notifications Area */}
          <div className="absolute top-4 right-4 z-[100] flex flex-col space-y-2 pointer-events-none">
            {notifications.map(n => (
              <div 
                key={n.id} 
                className="bg-black/80 backdrop-blur-md text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl animate-in fade-in slide-in-from-right-full duration-300 pointer-events-auto"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-[#E95420] rounded-full flex items-center justify-center text-[10px] font-bold">!</div>
                  <span className="text-sm font-medium">{n.text}</span>
                </div>
              </div>
            ))}
          </div>

          <div className="absolute inset-0 z-0" onContextMenu={(e) => e.preventDefault()}>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

