import React, { useState, useCallback, useEffect } from 'react';
import { AppID, WindowState } from './types';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import Window from './components/Window';
import GlobalSearch from './components/GlobalSearch';
import Terminal from './components/apps/Terminal';
import FileExplorer from './components/apps/FileExplorer';
import About from './components/apps/About';
import Browser from './components/apps/Browser';
import Settings from './components/apps/Settings';
import NeoBrowser from './components/apps/NeoBrowser';
import UbuntuDemo from './components/apps/UbuntuDemo';
import VLC from './components/apps/VLC';
import Orbital from './components/apps/Orbital';
import AIChat from './components/apps/AIChat';

const App: React.FC = () => {
  const [wallpaper, setWallpaper] = useState('https://picsum.photos/seed/ubuntu/1920/1080');
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'terminal', title: 'Terminal - Noyau Gemini', isOpen: true, isMaximized: false, zIndex: 10 },
    { id: 'ai-chat', title: 'Chat IA - Assistant Neuronal', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'files', title: 'Explorateur de fichiers', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'browser', title: 'Navigateur Web', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'neo-browser', title: 'NÉO WEB-EXPLORER', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'ubuntu-demo', title: 'Démo API Ubuntu', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'vlc', title: 'Lecteur Média VLC', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'orbital', title: 'Émulateur Orbital PS4', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'settings', title: 'Paramètres', isOpen: false, isMaximized: false, zIndex: 1 },
    { id: 'about', title: "À propos d'Ubuntu Intelligence", isOpen: false, isMaximized: false, zIndex: 1 },
  ]);
  const [highestZ, setHighestZ] = useState(10);
  const [notifications, setNotifications] = useState<{id: number, text: string}[]>([]);

  const addNotification = useCallback((text: string) => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, text }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const toggleApp = useCallback((id: AppID) => {
    setWindows(prev => {
      const exists = prev.find(w => w.id === id);
      const newHighestZ = highestZ + 1;
      setHighestZ(newHighestZ);

      if (exists) {
        return prev.map(w => w.id === id ? { ...w, isOpen: true, zIndex: newHighestZ } : w);
      } else {
        // Fallback title generation if not found in initial state
        const defaultTitle = id.charAt(0).toUpperCase() + id.slice(1);
        return [...prev, { id, title: defaultTitle, isOpen: true, isMaximized: false, zIndex: newHighestZ }];
      }
    });
  }, [highestZ]);

  const closeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false } : w));
  };

  const maximizeWindow = (id: AppID) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
  };

  const focusWindow = (id: AppID) => {
    if (windows.find(w => w.id === id)?.zIndex === highestZ) return;
    const newHighestZ = highestZ + 1;
    setHighestZ(newHighestZ);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, zIndex: newHighestZ } : w));
  };

  const getActiveApp = (): AppID | undefined => {
    const openWindows = windows.filter(w => w.isOpen).sort((a, b) => b.zIndex - a.zIndex);
    return openWindows.length > 0 ? openWindows[0].id : undefined;
  };

  const getAppIcon = (id: AppID) => {
    switch (id) {
      case 'terminal': return 'https://img.icons8.com/color/48/000000/terminal.png';
      case 'ai-chat': return 'https://img.icons8.com/fluency/48/robot-2.png';
      case 'files': return 'https://img.icons8.com/color/48/000000/folder-invoices.png';
      case 'browser': return 'https://img.icons8.com/color/48/000000/firefox.png';
      case 'neo-browser': return 'https://img.icons8.com/fluency/48/internet.png';
      case 'ubuntu-demo': return 'https://img.icons8.com/fluency/48/code.png';
      case 'vlc': return 'https://img.icons8.com/color/48/000000/vlc.png';
      case 'orbital': return 'https://img.icons8.com/fluency/48/controller.png';
      case 'settings': return 'https://img.icons8.com/color/48/000000/settings.png';
      case 'about': return 'https://img.icons8.com/color/48/000000/info--v1.png';
      default: return 'https://img.icons8.com/color/48/000000/ubuntu.png';
    }
  };

  useEffect(() => {
    const handleGlobalShortcuts = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'f') {
        e.preventDefault();
        setIsSearchOpen(prev => !prev);
      }
      if (e.key === 'Escape' && isSearchOpen) {
        setIsSearchOpen(false);
      }
    };

    window.addEventListener('keydown', handleGlobalShortcuts);
    return () => window.removeEventListener('keydown', handleGlobalShortcuts);
  }, [isSearchOpen]);

  useEffect(() => {
    addNotification("Intelligence Système initialisée. Le Chat IA est disponible.");
  }, [addNotification]);

  return (
    <div 
        className="h-screen w-screen flex flex-col overflow-hidden transition-all duration-1000 ease-in-out"
        style={{ 
            backgroundImage: `url('${wallpaper}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center'
        }}
    >
      <TopBar onSearchClick={() => setIsSearchOpen(true)} />

      <div className="flex-1 flex overflow-hidden">
        <Sidebar onAppClick={toggleApp} activeApp={getActiveApp()} />

        <main className="flex-1 relative overflow-hidden">
          {windows.map(window => (
            <Window
              key={window.id}
              id={window.id}
              title={window.title}
              isOpen={window.isOpen}
              isMaximized={window.isMaximized}
              zIndex={window.zIndex}
              onClose={() => closeWindow(window.id)}
              onMaximize={() => maximizeWindow(window.id)}
              onFocus={() => focusWindow(window.id)}
              icon={getAppIcon(window.id)}
            >
              {window.id === 'terminal' && <Terminal onAppOpen={toggleApp} addNotification={addNotification} />}
              {window.id === 'ai-chat' && <AIChat />}
              {window.id === 'files' && <FileExplorer />}
              {window.id === 'about' && <About />}
              {window.id === 'browser' && <Browser />}
              {window.id === 'neo-browser' && <NeoBrowser />}
              {window.id === 'ubuntu-demo' && <UbuntuDemo />}
              {window.id === 'vlc' && <VLC />}
              {window.id === 'orbital' && <Orbital />}
              {window.id === 'settings' && (
                <Settings 
                    currentWallpaper={wallpaper} 
                    onWallpaperChange={(url) => {
                        setWallpaper(url);
                        addNotification("Arrière-plan du bureau mis à jour.");
                    }} 
                />
              )}
            </Window>
          ))}

          <GlobalSearch 
            isOpen={isSearchOpen} 
            onClose={() => setIsSearchOpen(false)} 
            onSelect={toggleApp} 
          />

          {/* Notifications Area */}
          <div className="absolute top-4 right-4 z-[100] flex flex-col space-y-2 pointer-events-none">
            {notifications.map(n => (
              <div 
                key={n.id} 
                className="bg-black/80 backdrop-blur-md text-white px-4 py-2 rounded-lg border border-white/10 shadow-xl animate-in fade-in slide-in-from-right-full duration-300 pointer-events-auto"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-6 h-6 bg-[#E95420] rounded-full flex items-center justify-center text-[10px] font-bold">!</div>
                  <span className="text-sm font-medium">{n.text}</span>
                </div>
              </div>
            ))}
          </div>

          <div className="absolute inset-0 z-0" onContextMenu={(e) => e.preventDefault()}>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

const Browser: React.FC = () => {
  const defaultUrl = 'https://www.wikipedia.org';
  const [urlInput, setUrlInput] = useState(defaultUrl);
  const [iframeUrl, setIframeUrl] = useState(defaultUrl);
  const [history, setHistory] = useState<string[]>([defaultUrl]);
  const [isLoading, setIsLoading] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isCopied, setIsCopied] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const navigateTo = (url: string) => {
    let formattedUrl = url.trim();
    if (!formattedUrl.startsWith('http://') && !formattedUrl.startsWith('https://')) {
      formattedUrl = 'https://' + formattedUrl;
    }
    setIframeUrl(formattedUrl);
    setUrlInput(formattedUrl);
    setHistory(prev => {
      const newHistory = [formattedUrl, ...prev.filter(item => item !== formattedUrl)];
      return newHistory.slice(0, 20);
    });
    setIsHistoryOpen(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      navigateTo(urlInput);
    }
  };

  const handleLoad = () => {
    setIsLoading(false);
  };

  const clearHistory = () => {
    setHistory([iframeUrl]);
    setIsHistoryOpen(false);
  };

  const handleCopyUrl = async () => {
    try {
      await navigator.clipboard.writeText(urlInput);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy URL: ', err);
    }
  };

  return (
    <div className="h-full flex flex-col bg-white select-none">
      {/* Browser Toolbar */}
      <div className="h-12 bg-[#F2F2F2] border-b border-gray-300 flex items-center px-2 space-x-2 shrink-0 relative">
        <div className="flex items-center space-x-1 pr-2 border-r border-gray-300">
          <button 
            onClick={() => window.history.back()}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Précédent"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <button 
            onClick={() => window.history.forward()}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Suivant"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
          <button 
            onClick={() => {
              setIsLoading(true);
              const current = iframeUrl;
              setIframeUrl('');
              setTimeout(() => setIframeUrl(current), 10);
            }}
            className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
            title="Actualiser"
          >
            <svg className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        </div>

        {/* Address Bar */}
        <div className="flex-1 flex items-center bg-white border border-gray-300 rounded-full px-3 py-1 shadow-sm focus-within:ring-2 focus-within:ring-[#E95420]/30 focus-within:border-[#E95420] transition-all">
          <div className="text-gray-400 mr-2">
            <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <input 
            type="text"
            className="flex-1 bg-transparent border-none outline-none text-sm text-gray-700"
            value={urlInput}
            onChange={(e) => setUrlInput(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <button
            onClick={handleCopyUrl}
            className={`p-1 rounded-full transition-colors duration-200 ml-2 ${
                isCopied ? 'text-green-500' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'
            }`}
            title={isCopied ? "Copié !" : "Copier l'URL"}
          >
            {isCopied ? (
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
            ) : (
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                </svg>
            )}
          </button>
        </div>

        {/* History Button */}
        <div className="relative" ref={dropdownRef}>
          <button 
            onClick={() => setIsHistoryOpen(!isHistoryOpen)}
            className={`p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors ${isHistoryOpen ? 'bg-gray-200' : ''}`}
            title="Historique"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </button>

          {/* History Dropdown */}
          {isHistoryOpen && (
            <div className="absolute right-0 mt-2 w-72 bg-white border border-gray-200 rounded-lg shadow-xl z-50 overflow-hidden py-1">
              <div className="px-3 py-2 border-b border-gray-100 flex justify-between items-center">
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">Historique de navigation</span>
                <button 
                  onClick={clearHistory}
                  className="text-[10px] text-[#E95420] hover:underline font-medium"
                >
                  Tout effacer
                </button>
              </div>
              <div className="max-h-60 overflow-y-auto no-scrollbar">
                {history.length === 0 ? (
                  <div className="px-4 py-3 text-sm text-gray-400 italic">Aucun historique</div>
                ) : (
                  history.map((url, idx) => (
                    <button
                      key={idx}
                      onClick={() => navigateTo(url)}
                      className="w-full text-left px-4 py-2 text-sm hover:bg-gray-50 transition-colors truncate border-b border-gray-50 last:border-0"
                      title={url}
                    >
                      <div className="flex items-center space-x-2">
                        <svg className="w-3 h-3 text-gray-400 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101" />
                        </svg>
                        <span className="truncate text-gray-700">{url}</span>
                      </div>
                    </button>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        <button 
          onClick={() => navigateTo(defaultUrl)}
          className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
          title="Accueil"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
          </svg>
        </button>
      </div>

      {/* Security Info Bar */}
      <div className="bg-[#FFF9C4] text-[10px] px-4 py-0.5 text-[#827717] font-medium border-b border-[#FBC02D]/20 flex justify-between">
        <span>Certains sites peuvent bloquer l'intégration. Essayez Wikipedia ou Archive.org.</span>
        <span className="hidden sm:inline italic">Noyau Intelligence Firefox Ubuntu v1.0</span>
      </div>

      {/* Content Area */}
      <div className="flex-1 bg-gray-100 relative overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/80 z-10">
            <div className="flex flex-col items-center">
              <div className="w-8 h-8 border-4 border-[#E95420] border-t-transparent rounded-full animate-spin"></div>
              <span className="mt-2 text-xs font-medium text-gray-500 uppercase tracking-widest">Chargement...</span>
            </div>
          </div>
        )}
        <iframe 
          src={iframeUrl}
          className="w-full h-full border-none bg-white"
          onLoad={handleLoad}
          title="Browser Content"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
        />
      </div>
    </div>
  );
};

