import React, { useState, useEffect, useRef, useMemo } from 'react';
import { AppID, SearchResult } from '../types';

interface GlobalSearchProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (appId: AppID) => void;
}

const GlobalSearch: React.FC<GlobalSearchProps> = ({ isOpen, onClose, onSelect }) => {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const searchData: SearchResult[] = useMemo(() => [
    { id: 'app-terminal', type: 'app', label: 'Terminal', appId: 'terminal', icon: 'https://img.icons8.com/color/48/000000/terminal.png', description: 'Shell Principal IA Gemini' },
    { id: 'app-aichat', type: 'app', label: 'Chat IA', appId: 'ai-chat', icon: 'https://img.icons8.com/fluency/48/robot-2.png', description: 'Assistant IA dédié' },
    { id: 'app-files', type: 'app', label: 'Fichiers', appId: 'files', icon: 'https://img.icons8.com/color/48/000000/folder-invoices.png', description: 'Gestionnaire de fichiers Nautilus' },
    { id: 'app-browser', type: 'app', label: 'Navigateur Web', appId: 'browser', icon: 'https://img.icons8.com/color/48/000000/firefox.png', description: 'Navigateur Web Firefox' },
    { id: 'app-neo', type: 'app', label: 'NÉO Explorateur', appId: 'neo-browser', icon: 'https://img.icons8.com/fluency/48/internet.png', description: 'Explorateur Cyber-Intelligence' },
    { id: 'app-demo', type: 'app', label: 'App Démo', appId: 'ubuntu-demo', icon: 'https://img.icons8.com/fluency/48/code.png', description: 'Vitrine de composants React' },
    { id: 'app-vlc', type: 'app', label: 'Lecteur VLC', appId: 'vlc', icon: 'https://img.icons8.com/color/48/000000/vlc.png', description: 'Lecteur et streamer multimédia' },
    { id: 'app-orbital', type: 'app', label: 'Orbital PS4', appId: 'orbital', icon: 'https://img.icons8.com/fluency/48/controller.png', description: 'Émulateur matériel PS4' },
    { id: 'app-settings', type: 'app', label: 'Paramètres', appId: 'settings', icon: 'https://img.icons8.com/color/48/000000/settings.png', description: 'Configuration du système' },
    { id: 'app-about', type: 'app', label: 'À propos', appId: 'about', icon: 'https://img.icons8.com/color/48/000000/info--v1.png', description: 'Informations système' },
    { id: 'file-log', type: 'file', label: 'system_log.txt', appId: 'files', description: 'Fichier log dans /home/ubuntu/Documents' },
    { id: 'file-config', type: 'file', label: 'neural_net_config.json', appId: 'files', description: 'Config dans /home/ubuntu/AI_Assets' },
    { id: 'set-wall', type: 'setting', label: 'Changer le fond d\'écran', appId: 'settings', description: "Paramètres d'apparence" },
    { id: 'set-theme', type: 'setting', label: 'Mode Sombre', appId: 'settings', description: 'Thèmes système' },
  ], []);

  const filteredResults = useMemo(() => {
    if (!query.trim()) return [];
    return searchData.filter(item => 
      item.label.toLowerCase().includes(query.toLowerCase()) ||
      item.description?.toLowerCase().includes(query.toLowerCase())
    ).slice(0, 8);
  }, [query, searchData]);

  useEffect(() => {
    if (isOpen) {
      setQuery('');
      setSelectedIndex(0);
      setTimeout(() => inputRef.current?.focus(), 50);
    }
  }, [isOpen]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % filteredResults.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + filteredResults.length) % filteredResults.length);
    } else if (e.key === 'Enter') {
      if (filteredResults[selectedIndex]) {
        onSelect(filteredResults[selectedIndex].appId);
        onClose();
      }
    } else if (e.key === 'Escape') {
      onClose();
    }
  };

  if (!isOpen) return null;

  return (
    <div 
      className="fixed inset-0 z-[100] flex items-start justify-center pt-24 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200"
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div 
        ref={containerRef}
        className="w-full max-w-2xl bg-[#2D2D2D]/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 slide-in-from-top-4 duration-200"
      >
        <div className="flex items-center p-4 border-b border-white/5 bg-white/5">
          <svg className="w-6 h-6 text-[#E95420] mr-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input
            ref={inputRef}
            type="text"
            className="flex-1 bg-transparent border-none outline-none text-xl text-white placeholder-white/30 font-medium"
            placeholder="Rechercher des applications, fichiers ou paramètres..."
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              setSelectedIndex(0);
            }}
            onKeyDown={handleKeyDown}
          />
          <div className="flex items-center space-x-2 text-[10px] text-white/40 font-bold uppercase tracking-widest px-2 py-1 bg-white/5 rounded">
            <span>ESC</span>
          </div>
        </div>

        <div className="max-h-[450px] overflow-y-auto no-scrollbar py-2">
          {query.trim() === '' ? (
            <div className="p-10 text-center text-white/40">
              <div className="text-4xl mb-4 opacity-20">🔎</div>
              <p className="text-sm italic">Commencez à taper pour rechercher dans l'écosystème Intelligence.</p>
            </div>
          ) : filteredResults.length === 0 ? (
            <div className="p-10 text-center text-white/40">
              <p className="text-sm">Aucun résultat trouvé pour "{query}"</p>
            </div>
          ) : (
            <div className="px-2">
              {filteredResults.map((result, index) => (
                <button
                  key={result.id}
                  onClick={() => {
                    onSelect(result.appId);
                    onClose();
                  }}
                  onMouseEnter={() => setSelectedIndex(index)}
                  className={`w-full flex items-center p-4 rounded-xl transition-all duration-150 text-left group mb-1 ${
                    index === selectedIndex ? 'bg-[#E95420] text-white' : 'hover:bg-white/5 text-gray-300'
                  }`}
                >
                  <div className={`p-2 rounded-lg mr-4 bg-black/20 ${index === selectedIndex ? 'bg-white/20' : ''}`}>
                    {result.type === 'app' ? (
                      <img src={result.icon} className="w-8 h-8" alt="" />
                    ) : (
                      <span className="text-2xl w-8 h-8 flex items-center justify-center">
                        {result.type === 'file' ? '📄' : '⚙️'}
                      </span>
                    )}
                  </div>
                  <div className="flex-1">
                    <div className="font-bold">{result.label}</div>
                    <div className={`text-xs ${index === selectedIndex ? 'text-white/80' : 'text-white/40'}`}>
                      {result.description}
                    </div>
                  </div>
                  <div className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded bg-black/20 ${
                    index === selectedIndex ? 'text-white' : 'text-white/30'
                  }`}>
                    {result.type}
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="p-3 bg-black/20 border-t border-white/5 flex items-center justify-between text-[11px] text-white/30">
          <div className="flex items-center space-x-4">
            <span className="flex items-center"><span className="bg-white/10 px-1 rounded mr-1">↑↓</span> Naviguer</span>
            <span className="flex items-center"><span className="bg-white/10 px-1 rounded mr-1">Enter</span> Ouvrir</span>
          </div>
          <span>Interface de Recherche Ubuntu 24.04</span>
        </div>
      </div>
    </div>
  );
};

export default GlobalSearch;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { TerminalLine, AppID } from '../../types';
import { geminiService } from '../../services/geminiService';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';
import { Virtuoso, VirtuosoHandle } from 'react-virtuoso';

const commands = ['clear', 'help', 'whoami', 'info', 'pkg', 'sudo'];

const packageMap: Record<string, AppID> = {
  'file-explorer': 'files',
  'firefox': 'browser',
  'neo-browser': 'neo-browser',
  'ubuntu-demo': 'ubuntu-demo',
  'vlc': 'vlc',
  'orbital-ps4': 'orbital',
  'settings': 'settings',
  'about-ubuntu': 'about',
  'ai-chat': 'ai-chat'
};

const CopyButton: React.FC<{ text: string }> = ({ text }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy text: ', err);
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={`absolute top-2 right-2 p-1.5 rounded-md transition-all duration-200 opacity-0 group-hover:opacity-100 ${
        copied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
      }`}
      title="Copier dans le presse-papiers"
    >
      {copied ? (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
        </svg>
      ) : (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 S0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
        </svg>
      )}
    </button>
  );
};

const markdownComponents = {
  code({ node, inline, className, children, ...props }: any) {
    const match = /language-(\w+)/.exec(className || '');
    return !inline && match ? (
      <SyntaxHighlighter
        style={atomDark}
        language={match[1]}
        PreTag="div"
        {...props}
      >
        {String(children).replace(/\n$/, '')}
      </SyntaxHighlighter>
    ) : (
      <code className={className} {...props}>
        {children}
      </code>
    );
  },
};

const Terminal: React.FC<{ onAppOpen: (id: AppID) => void; addNotification: (text: string) => void }> = ({ onAppOpen, addNotification }) => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Bienvenue sur Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * Noyau IA:       Gemini 3 Flash' },
    { type: 'system', content: ' * Capacités:      Ancrage Web Complet, Synthèse de Commandes' },
    { type: 'system', content: '' },
    { type: 'system', content: "Ubuntu Intelligence prêt. Tapez `help` pour les commandes ou `Tab` pour l'auto-complétion." },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [allCopied, setAllCopied] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const virtuosoRef = useRef<VirtuosoHandle>(null);

  const handleCopyAll = async () => {
    const allText = lines.map(line => {
      if (line.type === 'input') return `ubuntu@intelligence:~$ ${line.content}`;
      return line.content;
    }).join('\n\n');

    try {
      await navigator.clipboard.writeText(allText);
      setAllCopied(true);
      setTimeout(() => setAllCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy all text: ', err);
    }
  };

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = inputValue.trim();
    if (!cmd || isProcessing) return;

    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setSuggestions([]);
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console effacée. Ubuntu Intelligence en attente.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [...prev, { type: 'output', content: "### Commandes :\n- **clear** : Effacer l'écran\n- **help** : Afficher ce message\n- **whoami** : Infos de session\n- **info** : Infos système\n- **pkg install [paquet]** : Installer une application\n- **sudo apt update** : Mise à jour système" }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'whoami') {
      setLines(prev => [...prev, { type: 'output', content: '**Utilisateur :** `ubuntu`\n**Shell :** `/bin/gemini-sh`' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.startsWith('pkg install')) {
      const pkg = cmd.split(' ')[2];
      const appId = packageMap[pkg];
      if (appId) {
        setLines(prev => [...prev, { type: 'system', content: `Installation de ${pkg}...` }]);
        addNotification(`Paquet '${pkg}' installé.`);
        setTimeout(() => {
          onAppOpen(appId);
          setIsProcessing(false);
        }, 1500);
      } else {
        setLines(prev => [...prev, { type: 'error', content: `Paquet non trouvé : ${pkg}` }]);
        setIsProcessing(false);
      }
      return;
    }

    const { text, sources } = await geminiService.processCommand(cmd);
    let output = text;
    if (sources && sources.length > 0) {
      output += '\n\n**Sources:**\n' + sources.map(s => `- [${s.title}](${s.uri})`).join('\n');
    }
    setLines(prev => [...prev, { type: 'output', content: output }]);
    setIsProcessing(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const matches = commands.filter(c => c.startsWith(inputValue));
      if (matches.length === 1) setInputValue(matches[0]);
      else if (matches.length > 1) setSuggestions(matches);
    }
  };

  const itemContent = useCallback((_index: number, line: TerminalLine) => (
    <div className="mb-2">
      {line.type === 'input' && (
        <div className="flex">
          <span className="text-[#87ff5f] font-bold mr-2">ubuntu@intelligence:~$</span>
          <span>{line.content}</span>
        </div>
      )}
      {line.type === 'output' && (
        <div className="relative group pl-2 border-l-2 border-[#E95420]/30 py-1">
          <ReactMarkdown components={markdownComponents} remarkPlugins={[remarkGfm]} className="terminal-markdown">
            {line.content}
          </ReactMarkdown>
          <CopyButton text={line.content} />
        </div>
      )}
      {line.type === 'system' && <div className="text-gray-400 italic text-xs">{line.content}</div>}
      {line.type === 'error' && <div className="text-red-400 font-bold">{line.content}</div>}
    </div>
  ), []);

  useEffect(() => {
    inputRef.current?.focus();
  }, [isProcessing]);

  return (
    <div className="h-full bg-[#300A24] text-white p-4 font-mono text-sm flex flex-col relative overflow-hidden" onClick={() => inputRef.current?.focus()}>
      <button onClick={handleCopyAll} className={`absolute top-2 right-4 p-1 rounded bg-white/5 hover:bg-white/10 z-10 transition-colors text-xs ${allCopied ? 'text-green-500' : 'text-gray-400'}`}>
        {allCopied ? 'Copié !' : 'Tout copier'}
      </button>

      <div className="flex-1 relative">
        <Virtuoso
          ref={virtuosoRef}
          data={lines}
          itemContent={itemContent}
          style={{ height: '100%' }}
          followOutput="auto"
        />
      </div>

      <div className="pt-2 shrink-0">
        {isProcessing && (
          <div className="flex items-center text-[#E95420] text-xs font-bold mb-1 animate-pulse">
            <span className="mr-2">●</span> CONSULTATION DU NOYAU NEURONAL...
          </div>
        )}
        <form onSubmit={handleCommand} className="flex items-center gap-2">
          <span className="text-[#87ff5f] font-bold mr-2 whitespace-nowrap">ubuntu@intelligence:~$</span>
          <input
            ref={inputRef}
            autoFocus
            className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0"
            value={inputValue}
            onChange={e => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            disabled={isProcessing}
          />
          <button type="submit" disabled={isProcessing || !inputValue.trim()} className="text-xs bg-[#E95420] text-white px-3 py-1 rounded-md hover:bg-[#d94410] disabled:bg-gray-500 disabled:opacity-50 transition-colors">
            Envoyer
          </button>
        </form>
        {suggestions.length > 0 && (
          <div className="mt-2 p-2 bg-black/30 rounded border border-white/10 flex gap-4 text-gray-400 text-xs">
            {suggestions.map(s => <span key={s}>{s}</span>)}
          </div>
        )}
      </div>
    </div>
  );
};

export default Terminal;

