                        </svg>
                        <span className="truncate text-gray-700">{url}</span>
                      </div>
                    </button>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        <button 
          onClick={() => navigateTo(defaultUrl)}
          className="p-1.5 hover:bg-gray-200 rounded text-gray-600 transition-colors"
          title="Accueil"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
          </svg>
        </button>
      </div>

      {/* Security Info Bar */}
      <div className="bg-[#FFF9C4] text-[10px] px-4 py-0.5 text-[#827717] font-medium border-b border-[#FBC02D]/20 flex justify-between">
        <span>Certains sites peuvent bloquer l'intégration. Essayez Wikipedia ou Archive.org.</span>
        <span className="hidden sm:inline italic">Noyau Intelligence Firefox Ubuntu v1.0</span>
      </div>

      {/* Content Area */}
      <div className="flex-1 bg-gray-100 relative overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/80 z-10">
            <div className="flex flex-col items-center">
              <div className="w-8 h-8 border-4 border-[#E95420] border-t-transparent rounded-full animate-spin"></div>
              <span className="mt-2 text-xs font-medium text-gray-500 uppercase tracking-widest">Chargement...</span>
            </div>
          </div>
        )}
        <iframe 
          src={iframeUrl}
          className="w-full h-full border-none bg-white"
          onLoad={handleLoad}
          title="Browser Content"
          sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
        />
      </div>
    </div>
  );
};

