import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';

interface Message {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
}

const AIChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { 
      role: 'model', 
      content: "Bonjour ! Je suis l'assistant IA d'Ubuntu Intelligence. Comment puis-je vous aider aujourd'hui ?", 
      timestamp: new Date() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatSession = useRef<Chat | null>(null);
  const [apiKeyError, setApiKeyError] = useState<boolean>(false);

  // Initialize Chat Session
  useEffect(() => {
    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) {
        console.warn("AIChat: API Key is missing.");
        setApiKeyError(true);
      }
      const ai = new GoogleGenAI({ apiKey: apiKey || '' });
      chatSession.current = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: "Tu es 'Ubuntu Intelligence Chat', un assistant IA souverain intégré dans un environnement Ubuntu 24.04. Tu es serviable, technique et précis. Utilise le formatage Markdown pour tes réponses.",
          temperature: 0.8,
        },
      });
    } catch (e) {
      console.error("Failed to initialize Gemini:", e instanceof Error ? e.message : String(e));
      setApiKeyError(true);
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isTyping) return;

    if (apiKeyError || !chatSession.current) {
         setMessages(prev => [...prev, {
            role: 'user',
            content: input,
            timestamp: new Date()
          }, {
            role: 'model',
            content: "⚠️ **Erreur de Configuration** : La clé API est manquante ou invalide. Veuillez configurer `process.env.API_KEY`.",
            timestamp: new Date()
          }]);
          setInput('');
          return;
    }

    const userMessage: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsTyping(true);

    try {
      const result = await chatSession.current.sendMessageStream({ message: input });

      let fullResponse = '';
      const aiMessage: Message = {
        role: 'model',
        content: '',
        timestamp: new Date()
      };

      setMessages(prev => [...prev, aiMessage]);

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        const chunkText = c.text || "";
        fullResponse += chunkText;

        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1] = {
            ...newMessages[newMessages.length - 1],
            content: fullResponse
          };
          return newMessages;
        });
      }
    } catch (error: any) {
      let errorMsg = "";
      try {
          // Careful with circular error objects often returned by APIs
          errorMsg = error?.message || String(error);
          if (error && typeof error === 'object' && !error.message) {
              errorMsg = JSON.stringify(error);
          }
      } catch {
          errorMsg = "Erreur de communication avec l'API.";
      }

      console.error("Chat Error:", error);

      let displayMessage = "Erreur système : Impossible de contacter le noyau neuronal.";

      // Handle 403 Forbidden specifically
      if (errorMsg.includes('403') || errorMsg.includes('PERMISSION_DENIED') || errorMsg.includes('permission')) {
        displayMessage = "⚠️ **Accès Refusé (403)**\n\nLe système n'a pas les permissions nécessaires pour accéder à l'API Gemini.\n\n**Solutions possibles :**\n1. Vérifiez que votre `API_KEY` est valide.\n2. Assurez-vous que l'API Gemini est activée pour votre projet Google Cloud.\n3. Vérifiez si vous avez dépassé vos quotas d'utilisation.\n\n*Contactez NetSecurePro pour l'assistance IA22.*";
        setApiKeyError(true);
      } else if (errorMsg.includes('503')) {
          displayMessage = "⚠️ **Service Indisponible (503)**\n\nLe service Gemini est temporairement surchargé. Veuillez réessayer dans quelques instants.";
      } else if (errorMsg.includes('400')) {
          displayMessage = "⚠️ **Requête Invalide (400)**\n\nLe message envoyé est malformé ou contient du contenu bloqué par les filtres de sécurité.";
      }

      setMessages(prev => [...prev, {
        role: 'model',
        content: displayMessage,
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const clearChat = () => {
    setMessages([{ 
      role: 'model', 
      content: "Session réinitialisée. En quoi puis-je vous être utile ?", 
      timestamp: new Date() 
    }]);
    setApiKeyError(false);
  };

  const markdownComponents = useMemo(() => ({
    code({ node, inline, className, children, ...props }: any) {
      const match = /language-(\w+)/.exec(className || '');

      // Sanitization: Remove 'node' and 'inline' from props before spreading to avoid circular reference errors in React internals
      const { node: _, inline: __, ...domProps } = props;

      return !inline && match ? (
        <SyntaxHighlighter
          style={atomDark}
          language={match[1]}
          PreTag="div"
        >
          {String(children).replace(/\n$/, '')}
        </SyntaxHighlighter>
      ) : (
        <code className={`bg-black/30 px-1 rounded text-orange-400 font-mono text-sm ${className || ''}`} {...domProps}>
          {children}
        </code>
      );
    },
  }), []);

  return (
    <div className="h-full flex flex-col bg-[#2D2D2D] text-gray-100 overflow-hidden font-sans">
      {/* Header Info */}
      <div className="bg-black/20 p-3 border-b border-white/5 flex justify-between items-center shrink-0">
        <div className="flex items-center space-x-2">
          <div className={`w-2 h-2 rounded-full ${apiKeyError ? 'bg-red-500' : 'bg-green-500 animate-pulse'}`}></div>
          <span className="text-xs font-bold uppercase tracking-widest text-white/60">Intelligence Core v3.0</span>
        </div>
        <button 
          onClick={clearChat}
          className="text-[10px] uppercase font-bold text-gray-400 hover:text-[#E95420] transition-colors"
        >
          Effacer la discussion
        </button>
      </div>

      {/* Message Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6 no-scrollbar">
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
          >
            <div className={`max-w-[85%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
              <div 
                className={`p-4 rounded-2xl shadow-lg relative ${
                  msg.role === 'user' 
                    ? 'bg-[#772953] text-white rounded-tr-none' 
                    : 'bg-[#3D3D3D] text-gray-100 border border-white/5 rounded-tl-none'
                }`}
              >
                <div className="terminal-markdown prose prose-invert prose-sm max-w-none">
                  <ReactMarkdown components={markdownComponents} remarkPlugins={[remarkGfm]}>
                    {msg.content}
                  </ReactMarkdown>
                </div>
              </div>
              <span className="text-[10px] mt-1 text-white/30 font-medium">
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-in fade-in duration-300">
            <div className="bg-[#3D3D3D] p-3 rounded-2xl rounded-tl-none border border-white/5 flex items-center space-x-2">
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce"></span>
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-1.5 h-1.5 bg-[#E95420] rounded-full animate-bounce [animation-delay:0.4s]"></span>
              <span className="text-xs text-white/40 italic pl-2">Système en réflexion...</span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-black/20 border-t border-white/5 shrink-0">
        <form onSubmit={handleSend} className="flex items-center space-x-3 bg-[#3D3D3D] rounded-xl p-1 border border-white/10 focus-within:border-[#E95420] transition-colors shadow-inner">
          <input
            type="text"
            className="flex-1 bg-transparent border-none outline-none px-4 py-2 text-sm text-white placeholder-white/30"
            placeholder={apiKeyError ? "Erreur API : Vérifiez votre clé." : "Posez votre question à l'intelligence centrale..."}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isTyping || apiKeyError}
          />
          <button
            type="submit"
            disabled={!input.trim() || isTyping || apiKeyError}
            className={`p-2 rounded-lg transition-all ${
              !input.trim() || isTyping || apiKeyError
                ? 'text-white/20' 
                : 'text-white bg-[#E95420] hover:bg-[#d94410] shadow-lg shadow-orange-900/20'
            }`}
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </form>
        <div className="mt-2 text-[9px] text-center text-white/20 uppercase tracking-[2px] font-bold">
          Gemini 3 Flash Powered Neural Interface
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useState, useRef, useEffect, useCallback, useMemo } from 'react';
import { TerminalLine, AppID } from '../../types';
import { geminiService } from '../../services/geminiService';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { atomDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import remarkGfm from 'remark-gfm';
import { Virtuoso, VirtuosoHandle } from 'react-virtuoso';

const commands = ['clear', 'help', 'whoami', 'info', 'pkg', 'sudo', 'snap'];

const packageMap: Record<string, AppID> = {
  'file-explorer': 'files',
  'firefox': 'browser',
  'neo-browser': 'neo-browser',
  'ubuntu-demo': 'ubuntu-demo',
  'vlc': 'vlc',
  'orbital-ps4': 'orbital',
  'settings': 'settings',
  'about-ubuntu': 'about',
  'ai-chat': 'ai-chat'
};

const CopyButton: React.FC<{ text: string }> = ({ text }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy text: ', err instanceof Error ? err.message : String(err));
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={`absolute top-2 right-2 p-1.5 rounded-md transition-all duration-200 opacity-0 group-hover:opacity-100 ${
        copied ? 'bg-green-600 text-white' : 'bg-white/10 text-gray-400 hover:bg-white/20 hover:text-white'
      }`}
      title="Copier dans le presse-papiers"
    >
      {copied ? (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
        </svg>
      ) : (
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
        </svg>
      )}
    </button>
  );
};

const Terminal: React.FC<{ onAppOpen: (id: AppID) => void; addNotification: (text: string) => void }> = ({ onAppOpen, addNotification }) => {
  const [lines, setLines] = useState<TerminalLine[]>([
    { type: 'system', content: 'Bienvenue sur Ubuntu 24.04 LTS (GNU/Linux 6.8.0-generic x86_64)' },
    { type: 'system', content: ' * Noyau IA:       Gemini 3 Flash' },
    { type: 'system', content: ' * Capacités:      Ancrage Web Complet, Synthèse de Commandes' },
    { type: 'system', content: '' },
    { type: 'system', content: "Ubuntu Intelligence prêt. Tapez `help` pour les commandes ou `Tab` pour l'auto-complétion." },
    { type: 'system', content: '' },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [allCopied, setAllCopied] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);
  const virtuosoRef = useRef<VirtuosoHandle>(null);

  const handleCopyAll = async () => {
    const allText = lines.map(line => {
      if (line.type === 'input') return `ubuntu@intelligence:~$ ${line.content}`;
      return line.content;
    }).join('\n\n');

    try {
      await navigator.clipboard.writeText(allText);
      setAllCopied(true);
      setTimeout(() => setAllCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy all text: ', err instanceof Error ? err.message : String(err));
    }
  };

  const simulateInstall = async (pkg: string, appId: AppID, manager: string) => {
    const steps = [
      { msg: `Lecture des listes de paquets... Fait`, delay: 400 },
      { msg: `Construction de l'arbre des dépendances... Fait`, delay: 300 },
      { msg: `Lecture de l'information d'état... Fait`, delay: 300 },
      { msg: `Les NOUVEAUX paquets suivants seront installés :`, delay: 200 },
      { msg: `  ${pkg}`, delay: 100 },
      { msg: `0 mis à jour, 1 nouvellement installés, 0 à enlever et 0 non mis à jour.`, delay: 200 },
      { msg: `Il est nécessaire de prendre 14,2 Mo dans les archives.`, delay: 200 },
      { msg: `Après cette opération, 48,6 Mo d'espace disque supplémentaires seront utilisés.`, delay: 200 },
      { msg: `Réception de :1 http://archive.ubuntu.com/ubuntu noble/main amd64 ${pkg} [14,2 MB]`, delay: 800 },
      { msg: `Progress: [##########----------] 50%`, delay: 400 },
      { msg: `Progress: [####################] 100%`, delay: 400 },
      { msg: `Sélection du paquet ${pkg} précédemment désélectionné.`, delay: 300 },
      { msg: `(Lecture de la base de données... 184522 fichiers et répertoires déjà installés.)`, delay: 500 },
      { msg: `Préparation du dépaquetage de .../${pkg}_amd64.deb ...`, delay: 400 },
      { msg: `Dépaquetage de ${pkg} (2.4.0-ubuntu1) ...`, delay: 600 },
      { msg: `Paramétrage de ${pkg} (2.4.0-ubuntu1) ...`, delay: 500 },
      { msg: `Traitement des actions différées (« triggers ») pour systemd (255.4-1ubuntu8) ...`, delay: 400 },
      { msg: `Traitement des actions différées (« triggers ») pour man-db (2.12.0-4build2) ...`, delay: 300 },
      { msg: `Installation terminée pour ${pkg}.`, delay: 200 },
    ];

    for (const step of steps) {
      setLines(prev => [...prev, { type: 'system', content: step.msg }]);
      await new Promise(resolve => setTimeout(resolve, step.delay));
    }

    addNotification(`Succès : ${pkg} a été installé via ${manager}.`);
    onAppOpen(appId);
    setIsProcessing(false);
  };

  const handleCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = inputValue.trim();
    if (!cmd || isProcessing) return;

    setLines(prev => [...prev, { type: 'input', content: cmd }]);
    setInputValue('');
    setSuggestions([]);
    setIsProcessing(true);

    if (cmd.toLowerCase() === 'clear') {
      setLines([{ type: 'system', content: 'Console effacée. Ubuntu Intelligence en attente.' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'help') {
      setLines(prev => [...prev, { type: 'output', content: "### Commandes :\n- **clear** : Effacer l'écran\n- **help** : Afficher ce message\n- **whoami** : Infos de session\n- **info** : Infos système\n- **pkg install [paquet]** : Installer une application\n- **snap install [paquet]** : Installer une application via snap\n- **sudo apt update** : Mise à jour système" }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.toLowerCase() === 'whoami') {
      setLines(prev => [...prev, { type: 'output', content: '**Utilisateur :** `ubuntu`\n**Shell :** `/bin/gemini-sh`' }]);
      setIsProcessing(false);
      return;
    }

    if (cmd.startsWith('pkg install') || cmd.startsWith('snap install') || cmd.startsWith('sudo apt install')) {
      const parts = cmd.split(' ');
      const pkg = parts[parts.length - 1];
      const manager = parts[0] === 'sudo' ? 'apt' : parts[0];
      const appId = packageMap[pkg];

      if (appId) {
        await simulateInstall(pkg, appId, manager);
      } else {
        setLines(prev => [...prev, { type: 'error', content: `E: Impossible de trouver le paquet ${pkg}` }]);
        setIsProcessing(false);
      }
      return;
    }

    try {
        const { text, sources } = await geminiService.processCommand(cmd);
        let output = text;
        if (sources && sources.length > 0) {
        output += '\n\n**Sources:**\n' + sources.map(s => `- [${s.title}](${s.uri})`).join('\n');
        }
        setLines(prev => [...prev, { type: 'output', content: output }]);
    } catch (err) {
        setLines(prev => [...prev, { type: 'error', content: `Erreur interne: ${String(err)}` }]);
    } finally {
        setIsProcessing(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const matches = commands.filter(c => c.startsWith(inputValue));
      if (matches.length === 1) setInputValue(matches[0]);
      else if (matches.length > 1) setSuggestions(matches);
    }
  };

  const markdownComponents = useMemo(() => ({
    code({ node, inline, className, children, ...props }: any) {
      const match = /language-(\w+)/.exec(className || '');

      // Sanitization: Remove 'node' and 'inline' before spreading props to avoid circular structure errors
      const { node: _, inline: __, ...domProps } = props;

      return !inline && match ? (
        <SyntaxHighlighter
          style={atomDark}
          language={match[1]}
          PreTag="div"
        >
          {String(children).replace(/\n$/, '')}
        </SyntaxHighlighter>
      ) : (
        <code className={className} {...domProps}>
          {children}
        </code>
      );
    },
  }), []);

  const itemContent = useCallback((_index: number, line: TerminalLine) => (
    <div className="mb-2">
      {line.type === 'input' && (
        <div className="flex">
          <span className="text-[#87ff5f] font-bold mr-2">ubuntu@intelligence:~$</span>
          <span>{line.content}</span>
        </div>
      )}
      {line.type === 'output' && (
        <div className="relative group pl-2 border-l-2 border-[#E95420]/30 py-1">
          <ReactMarkdown components={markdownComponents} remarkPlugins={[remarkGfm]} className="terminal-markdown">
            {line.content}
          </ReactMarkdown>
          <CopyButton text={line.content} />
        </div>
      )}
      {line.type === 'system' && <div className="text-gray-400 italic text-xs leading-relaxed">{line.content}</div>}
      {line.type === 'error' && <div className="text-red-400 font-bold">{line.content}</div>}
    </div>
  ), [markdownComponents]);

  useEffect(() => {
    inputRef.current?.focus();
  }, [isProcessing]);

  return (
    <div className="h-full bg-[#300A24] text-white p-4 font-mono text-sm flex flex-col relative overflow-hidden" onClick={() => inputRef.current?.focus()}>
      <button onClick={handleCopyAll} className={`absolute top-2 right-4 p-1 rounded bg-white/5 hover:bg-white/10 z-10 transition-colors text-xs ${allCopied ? 'text-green-500' : 'text-gray-400'}`}>
        {allCopied ? 'Copié !' : 'Tout copier'}
      </button>

      <div className="flex-1 relative">
        <Virtuoso
          ref={virtuosoRef}
          data={lines}
          itemContent={itemContent}
          style={{ height: '100%' }}
          followOutput="auto"
        />
      </div>

      <div className="pt-2 shrink-0 border-t border-white/5 mt-2">
        {isProcessing && (
          <div className="flex items-center text-[#E95420] text-xs font-bold mb-1 animate-pulse">
            <span className="mr-2">●</span> OPÉRATION SYSTÈME EN COURS...
          </div>
        )}
        <form onSubmit={handleCommand} className="flex items-center gap-2">
          <span className="text-[#87ff5f] font-bold mr-2 whitespace-nowrap">ubuntu@intelligence:~$</span>
          <input
            ref={inputRef}
            autoFocus
            className="bg-transparent border-none outline-none flex-1 text-white p-0 m-0"
            value={inputValue}
            onChange={e => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            disabled={isProcessing}
          />
          <button type="submit" disabled={isProcessing || !inputValue.trim()} className="text-xs bg-[#E95420] text-white px-3 py-1 rounded-md hover:bg-[#d94410] disabled:bg-gray-500 disabled:opacity-50 transition-colors">
            Entrée
          </button>
        </form>
        {suggestions.length > 0 && (
          <div className="mt-2 p-2 bg-black/30 rounded border border-white/10 flex gap-4 text-gray-400 text-xs">
            {suggestions.map(s => <span key={s}>{s}</span>)}
          </div>
        )}
      </div>
    </div>
  );
};

export default Terminal;
